  {key="f_aravind-srinivas", effect_brief="1st clean hand/blind (all distinct Layers): +40 Users", set="Founder", name="Doorstep Closer", short="Closer", ability_name="Send Them A Link", ability_text="The Doorstep Closer camped outside a professor's door with nothing but a live product and walked out with a check — no slides, no padding. The first hand each blind where every tech you ship is a distinct Layer (a lean stack, no redundancy), gain +40 Users. Ship the raw product and let it speak for itself.", rarity="Common", salary=5, groups={"ex-openai", "ai-engineer-wave", "ex-openai-diaspora", "uc-berkeley-ai-lab", "openai-alumni"}, hint="Burst of +Users when you ship a raw hand…", effect={type="plus_chips", scaling="conditional_burst", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="40 if all_played_cards_unenhanced_and_unsealed else 0", ke_complement=false}, dsl={hook="joker_main", gate={g="all_distinct_layers"}, once=true, once_scope="blind", ops={{k="scale", field="chips", base=40}}}},
  {key="f_arthur-mensch", effect_brief="xRev when under 70% target; ante3+ on-target copies best card", set="Founder", name="Torrent Polytechnicien", short="Polytechnici", ability_name="Compute-Optimal Release", ability_text="The Torrent Polytechnicien shipped a magnet link instead of a press release — the math had already won. Ship under 70% of the blind's target and gain a bonus xRev of (1 + the shortfall) — efficiency over overbuilt overkill. From the IPO-track stages (ante 3+), any on-target Ship triggers Open Weights: copy your highest-value tech card back into the deck.", rarity="Common", salary=5, groups={"ecole-polytechnique-alumni", "french-ai-founders", "ex-deepmind", "french-ai-ecosystem"}, hint="+Users (Users) scaling — bonus proportion…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={ {gate={g="arr_ratio", stage="pre_after", op="<", val=0.7}, k="scale", field="x_mult", base=2, coef=-1, per="arr_ratio"}, {gate={g="and", gs={ {g="arr_ratio", stage="pre_after", op=">=", val=0.7}, {g="ante", op=">=", val=3} }}, k="gen", kind="copy_card", which="highest"} }}},
  {key="f_arthur-rock", effect_brief="+1 Rev/Round held (permanent); x1.5 Rev while 3+ Founders", set="Founder", name="Four-Page Magna Carta", short="Carta", ability_name="Back the Right People", ability_text="The Four-Page Magna Carta skipped the financials and bet on the people. Hold this Founder and it compounds: +1 Rev permanently for every Round it has been on your bench (banked once per Round, never resets). And while you keep a full bench of 3 or more Founders active, all of your Rev is multiplied by x1.5. Patient capital — recruit early, hold long, and back a deep team.", rarity="Rare", salary=20, hint="Scaling-over-time (grows each round held)…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="hold", when="post", step="round"}, {k="scale", field="x_mult", base=1.5, gate={g="count", per="others", op=">=", val=2}}}}},
  {key="f_arvid-lunnemark", effect_brief="Blocks 1 clash/blind, no penalty", set="Founder", name="Ghost Forker", short="Forker", ability_name="Iterate to Clean", ability_text="The Ghost Forker built a shadow world to test changes before they ever touched the live session — then left a $29B rocket to apply the same principle at civilizational scale. Once per blind, if your played hand would suffer a compatibility penalty, the shadow workspace intercepts: the clash is silently resolved and those cards score without the penalty. Exactly one intercept per blind, then the shadow resets.", rarity="Common", salary=5, groups={"mit-class-of-2022", "ioi-alumni"}, hint="once per blind, absorb one compatibility…", effect={type="utility", scaling="conditional_burst", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="1 clash negated per blind (no score number; removes compati…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", amount=1}}, once=true, once_scope="blind"}},
  {key="f_ashish-vaswani", effect_brief="×2.5 Rev if all Layers distinct", set="Founder", name="Quiet Abolisher", short="Abolisher", ability_name="Attention Is All You Need", ability_text="The Quiet Abolisher threw out the old architecture entirely and let every part of the stack talk to every other part simultaneously. If your played hand contains Tech cards spanning every distinct Layer in your hand with no Layer repeated, the Transformer fires: Rev is multiplied by ×2.5 for that scoring. Full parallel coverage, nothing left out.", rarity="Rare", salary=20, groups={"transformer-paper-authors", "ex-google-brain-diaspora", "transformer-eight", "ex-google-ai-diaspora"}, hint="xmult conditional_burst: if every played…", effect={type="xmult", scaling="conditional_burst", hook="individual", primitive_hint="x_mult", engine_status="executable", magnitude="x2.5 if count(distinct_layers_in_played_hand) == count(card…", ke_complement=false}, dsl={hook="joker_main", gate={g="all_distinct_layers"}, ops={{k="scale", field="x_mult", base=2.5, coef=0}}}},
  {key="f_azalia-mirhoseini", effect_brief="On Ship: dissolve clashes equal to current Ante", set="Founder", name="Board Whisperer", short="Whisperer", ability_name="Floorplan Cleared", ability_text="The Board Whisperer doesn't argue with critics — she lets five generations of shipping hardware make the case. While she's on the board, each Ante she smooths over more of your deck's friction: when you Ship, dissolve compatibility clashes equal to your current Ante before the score is tallied. By Ante 8 even a janky multi-layer stack ships like a frictionless machine, with the clash haircut all but gone.", rarity="Uncommon", salary=10, groups={"deepmind-alumni"}, hint="permanently clears one compatibility clas…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="cleared_clashes = blinds_survived (max 1 new edge cleared p…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", per="ante", base=0, coef=1}}}},
  {key="f_ben-dunphy", effect_brief="+1 Rev per other hired Founder", set="Founder", name="Room Whisperer", short="Whisperer", ability_name="The Summit Effect", ability_text="The Room Whisperer finds the venue through an old contact, falls in love with the sight lines, and proves every skeptic wrong the moment the doors open. While hired, each other hired Founder grants +1 Rev at scoring time — because the right room amplifies everyone already in it.", rarity="Common", salary=5, groups={"ai-engineer-wave"}, hint="+Rev scaling with hired Founders (commun…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0.0, coef=1.0, per="others"}}}},
  {key="f_ben-horowitz", effect_brief="Once, when behind: sell top card, Cash = half hand ARR", set="Founder", name="Wartime Undertaker", short="Undertaker", ability_name="Oxide Protocol", ability_text="The Wartime Undertaker watched his own company roll out the loading dock and used the wreckage to fund the resurrection. Once per run, when you fall short on a blind (ARR below target): liquidate your strongest tech card and raise emergency Cash equal to half of this hand's ARR. The wartime pivot is earned, not farmed. One-shot.", rarity="Uncommon", salary=10, groups={"a16z-leadership"}, hint="Cash generation from failed/surplus cards…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op="<", val=1.0}, ops={{k="gen", kind="remove_card", which="highest"}, {k="scale", field="dollars", per="running_arr", stage="pre_after", coef=0.5}}, once=true, once_scope="run"}},
  {key="f_ben-mann", effect_brief="Overkill >1.5× converts surplus to Cash", set="Founder", name="Billion-Dollar Middleware", short="Middleware", ability_name="Tech Transfer", ability_text="The Billion-Dollar Middleware took a research breakthrough sitting in a GPU cluster and turned it into a deployment deal. When you Ship a hand scoring more than 1.5× the blind's target ARR, the excess above the target converts to Cash at a 1:3 ratio. Triggers once per blind — build the strong, well-fitted hand first, then collect the conversion.", rarity="Uncommon", salary=10, groups={"ex-openai-diaspora", "anthropic-founding-team"}, hint="overkill ARR → Cash conversion", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", gate={g="arr_ratio", stage="pre_after", op=">", val=1.5}, once=true, once_scope="blind", ops={{k="grant", what="cash", per="overkill", coef=0.333}}}},
  {key="f_bill-gates", effect_brief="+0.2 ×Rev perm per ship", set="Founder", name="Mugshot Magnate", short="Magnate", ability_name="Clone-Maker Standard", ability_text="The Mugshot Magnate made every clone-maker a distribution channel instead of a threat. Clone-Maker Standard gains +0.2 ×Rev permanently each time you Ship, and applies that accumulating multiplier to your Revenue-per-user when scored. The more you ship across the run, the heavier the standard-bearer's multiplier you carry into every score.", rarity="Legendary", salary=40, groups={"lakeside-programming-group"}, hint="Permanent xmult that grows every time you…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.2*ships_this_run", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.2, per="ships_this_run"}}}},
  {key="f_bill-hewlett", effect_brief="-1 Salary/round; idle Layer +8 Users ea", set="Founder", name="Bolt-Cutter Boss", short="Boss", ability_name="Open Lab Stock", ability_text="The Bolt-Cutter Boss arrived on a weekend, found the lock on the stockroom, and cut it off — then left a note. While hired, Salary cost is reduced by 1 each round. Once per Ship, if you hold at least 3 tech cards of the same Layer unplayed, those idle cards each contribute +8 Users — engineers with open access to the bench create innovations on their own time that directly benefit the product.", rarity="Rare", salary=20, hint="Salary reduction + conditional +Users sca…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={passive={what="salary", amount=1.0}, hook="joker_main", ops={{k="scale", field="chips", per="cards_of_layer_in_hand", layer="Frontend", coef=8, gate={g="count", per="cards_of_layer_in_hand", layer="Frontend", op=">=", val=3}}, {k="scale", field="chips", per="cards_of_layer_in_hand", layer="Backend", coef=8, gate={g="count", per="cards_of_layer_in_hand", layer="Backend", op=">=", val=3}}, {k="scale", field="chips", per="cards_of_layer_in_hand", layer="Data", coef=8, gate={g="count", per="cards_of_layer_in_hand", layer="Data", op=">=", val=3}}, {k="scale", field="chips", per="cards_of_layer_in_hand", layer="Infra", coef=8, gate={g="count", per="cards_of_layer_in_hand", layer="Infra", op=">=", val=3}}, {k="scale", field="chips", per="cards_of_layer_in_hand", layer="AI", coef=8, gate={g="count", per="cards_of_layer_in_hand", layer="AI", op=">=", val=3}}}}},
  {key="f_bill-joy", effect_brief="While held: ignore ALL clashes (no clash Rev haircut)", set="Founder", name="Stack Arsonist", short="Arsonist", ability_name="Scratch-Stack Mandate", ability_text="The Stack Arsonist looked at the contracted code, decided it was wrong, and rewrote the whole networking layer from scratch. While held, your played tech stack is treated as fully compatible: ALL compatibility-graph clashes are ignored during scoring (no clash Rev haircut). Flat and always-on.", rarity="Rare", salary=20, hint="utility — removes compatibility clashes o…", effect={type="utility", scaling="flat", hook="held", primitive_hint=nil, engine_status="data_only", magnitude="ignore_compat_clashes(layers=[Infra,Backend])", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", amount="all"}}}},
  {key="f_biz-stone", effect_brief="+2 Rev perm each round you hold back 3+ cards", set="Founder", name="Two-Million-Dollar Quit", short="Quit", ability_name="Brand Voice", ability_text="The Two-Million-Dollar Quit walked out of the obvious win grinning — the little play down the hall was the one that mattered. While hired, each round you ship a lean hand that holds back 3 or more cards (principled restraint, not chasing the big stack), this Founder gains +2 Rev permanently. Opportunity is manufactured by declining the easy play.", rarity="Common", salary=5, groups={"twitter-founders", "twitter-cofounders", "Odeo crew", "Blogger team"}, hint="+Rev (scaling) conditioned on neutral/pr…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0.0, coef=2.0, state="plus_mult", when="post", step="round", gate={g="count", per="unplayed_cards", op=">=", val=3}}}}},
  {key="f_blake-ross", effect_brief="+8+(4×rounds) Users, grows each round", set="Founder", name="Invisible Architect", short="Architect", ability_name="Download Cascade", ability_text="The Invisible Architect seeded bloggers first, let them pull in the tech press, which pulled the mainstream, which the community then amplified with its own money — and kept his own name out of it until a magazine cover ambushed him at breakfast. Each round this Founder is held, gain +(8 + 4 × rounds_held) Users when scoring. The longer he stays in the lineup, the further into the mainstream the wave has propagated.", rarity="Common", salary=5, hint="+Users growing each round held; each wave…", effect={type="plus_chips", scaling="scaling_per_round", hook="held", primitive_hint="chips", engine_status="executable", magnitude="8 + 4 * rounds_held", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="chips", base=8.0, coef=4.0, per="rounds_held"}}}},
  {key="f_bob-frankston", effect_brief="Surplus ARR→Cash 1:1; -$2 payroll/round while hired", set="Founder", name="Midnight Assembler", short="Assembler", ability_name="Overnight Efficiency Run", ability_text="The Midnight Assembler booked the cheap time-sharing shifts after midnight, slept through the day, and packed a world-changing application into 20KB. When your shipped product exceeds the blind's ARR target, all surplus ARR converts to Cash at 1:1 instead of being wasted. While he sits on your bench, his lean habits cut $2 off your payroll each round. Do more with less; bill when the rates are low.", rarity="Common", salary=5, hint="Cash generation from overkill ARR + Salar…", effect={type="economy", scaling="flat", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="cash", per="overkill", coef=1.0}}, passive={what="salary", amount=2}}},
  {key="f_bob-kagle", effect_brief="+2 Margin per new Layer 1st played; +1 Founder slot", set="Founder", name="Lure That Lost", short="Lost", ability_name="Felt the Hook", ability_text="The Lure That Lost browsed a site alone after the meeting, found a hand-carved fishing lure from his hometown, bid on it, and lost — and that defeat convinced him to wire the money in the morning. The first time a card from each new Layer is played in a run, gain +2 Margin permanently. While hired, you have +1 Founder slot.", rarity="Common", salary=5, hint="conditional +Rev scaling when you person…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={passive={what="founder_slots", amount=1}, hook="joker_main", ops={{k="grant", what="margin", per="new_layers", coef=0.08}}}},
  {key="f_bono", effect_brief="+1 Rev perm each Ship that barely clears its target", set="Founder", name="Glaucoma Dealmaker", short="Dealmaker", ability_name="Brand Equity Play", ability_text="The Glaucoma Dealmaker turns lean rounds into lasting leverage — the worse the economics look on paper, the bigger the long-term flywheel. Whenever you Ship a round that only just clears its target (running ARR within 115% of the blind, i.e. barely break-even with little overkill), gain +1 Rev permanently. Stacks with no cap: scraping by today is brand equity compounding tomorrow.", rarity="Common", salary=5, hint="scaling ×Rev from voluntarily under-mone…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="plus_mult", when="post", step="ship", gate={g="arr_ratio", stage="pre_after", op="<=", val=1.15}}}}},
  {key="f_bret-taylor", effect_brief="Overkill 20%+: Cash+Margin grows +1%", set="Founder", name="Board Whisperer", short="Whisperer", ability_name="Outcome-Based Billing", ability_text="The Board Whisperer only charges on genuine over-delivery — outcomes, not effort. Whenever your played hand's ARR exceeds the blind target by 20% or more, convert the surplus ARR into Cash equal to (surplus ÷ 10, rounded up), and permanently raise Margin by +1% (stacks, max +5%). If you just meet the blind with no overkill, the bonus does not fire.", rarity="Uncommon", salary=10, hint="Overkill ARR → Cash + board-level Margin…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", gate={g="arr_ratio", stage="pre_after", op=">=", val=1.2}, ops={{k="grant", what="cash", per="overkill", coef=0.1}, {k="grant", what="margin", amount=0.01, max=0.05}}}},
  {key="f_brewster-kahle", effect_brief="Each hand: dissolve 1 clash + 1 per blind Shipped this run", set="Founder", name="Infinite Librarian", short="Librarian", ability_name="Wayback Immunity", ability_text="The Infinite Librarian archives every broken dependency it has ever seen. On each scoring hand it absorbs 1 layer-compatibility clash, plus 1 more for every blind you have already Shipped this run — so the more milestones behind you, the more of your deck's roughest misfits score without friction.", rarity="Common", salary=5, hint="Permanently neutralises one layer-compati…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 clash archived per blind Shipped (cumulative; uncapped)", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", per="ships_this_run", base=1, coef=1}}}},
  {key="f_brian-chesky", effect_brief="×0.1 Rev per hand; lost if sold", set="Founder", name="Cereal Gambit", short="Gambit", ability_name="Founder Mode", ability_text="The Cereal Gambit stayed in the room every round and refused to hand off — every time founders step away, the compounding stops. At the start of each hand played while hired, the current ×Rev bonus increases by ×0.1 (stacks across all hands played this run). The multiplier is lost permanently if Cereal Gambit is ever sold: you cannot delegate your way back.", rarity="Uncommon", salary=10, hint="xMult that grows each round Cereal Gambit…", effect={type="xmult", scaling="scaling_per_round", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.1 + 0.1 * hands_played_while_hired", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.0, coef=0.1, state="xmult", when="post", max=40}}}},
  {key="f_bruce-dunlevie", effect_brief="+20 Users if hand < full size", set="Founder", name="Lone Nay", short="Nay", ability_name="The Lone Nay Dividend", ability_text="The Lone Nay knows when to hold back — the governance counselor's reward for restraint. If the hand you just scored used fewer cards than your full hand size, immediately add +20 Users to this scoring round. Fires once per round you practice restraint; does not trigger on a full-hand play.", rarity="Common", salary=5, hint="plus_chips: if you played fewer cards tha…", effect={type="plus_chips", scaling="conditional_burst", hook="after", primitive_hint="chips", engine_status="executable", magnitude="+20 chips if cards_played < hand_size", ke_complement=false}, dsl={hook="after", gate={g="count", per="unplayed_cards", op=">", val=0}, once=true, once_scope="blind", ops={{k="scale", field="chips", base=20, coef=0}}}},
  {key="f_caterina-fake", effect_brief="+8 Users/round, grows each round", set="Founder", name="Culture Framer", short="Framer", ability_name="Fifty Posts a Day", ability_text="The Culture Framer shows up every round and sets the tone — the norms you model at launch ripple outward as the community scales. At the end of each round this founder is in play, gain +8 permanent Users (Users). Held long enough across a run, the banked Users compound into a decisive User pool, rewarding the founder who shows up every round and never flinches.", rarity="Common", salary=5, hint="+Users permanently each round held (commu…", effect={type="plus_chips", scaling="scaling_persistent", hook="after", primitive_hint="chips", engine_status="executable", magnitude="8 per round held (permanent)", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="chips", base=0.0, coef=8, state="plus_chips", when="post", step="round"}}}},
  {key="f_chad-hurley", effect_brief="+$1 Cash per new App Type shipped", set="Founder", name="Iframe Bandit", short="Bandit", ability_name="Zero-Budget Billboard", ability_text="The Iframe Bandit never had a marketing budget — so he made the product the billboard. Each time a new App Type is Shipped for the first time this run, permanently add $1 to this card's passive Cash payout (paid after each round). The counter never resets: the wider your tech stack, the more embedded the revenue.", rarity="Uncommon", salary=10, groups={"paypal-mafia"}, mafia=true, hint="permanently gains $1 Cash per distinct Ap…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="1 * distinct_app_types_shipped_this_run", ke_complement=false}, dsl={hook="pre_cash_out", ops={{k="scale", field="dollars", base=0, coef=1, per="distinct_app_types_shipped"}}}},
  {key="f_charles-geschke", effect_brief="2+-Layer hands dissolve clashes: 1 per extra Layer", set="Founder", name="Living Standard", short="Standard", ability_name="Working Prototype", ability_text="The Living Standard turned interoperability into a moat. Each time you Ship a hand spanning 2 or more distinct Layers, compatibility clashes among the played Layers dissolve for that hand — one fewer clash for each Layer beyond the first you cover. The broader the stack you prove you can run, the more your tools simply work together, one licensee at a time.", rarity="Uncommon", salary=10, hint="Permanently removes one compatibility cla…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 clash resolved per qualifying hand; max resolvable clashe…", ke_complement=false}, dsl={hook="before", gate={g="count", per="distinct_layers", op=">=", val=2}, ops={{k="clear_clash", per="distinct_layers", base=-1, coef=1}}}},
  {key="f_charles-packer", effect_brief="+2 Users/played card per round held (compounds over time)", set="Founder", name="Midnight Pager", short="Pager", ability_name="Virtual Context Window", ability_text="The Midnight Pager keeps your hot context paged in — the longer you've been building, the more value the right tool delivers. Each card you play gains +2 Users for every round the Pager has been hired. The bonus compounds the longer you keep it on the team.", rarity="Common", salary=5, groups={"uc-berkeley-sky-lab", "ai-engineer-wave"}, hint="scaling-over-time (grows each Ship) + con…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="individual", ops={{k="scale", field="chips", base=0, coef=2, per="rounds_held"}}}},
  {key="f_chi-wang", effect_brief="Retriggers +1 extra per round held", set="Founder", name="Super Router", short="Router", ability_name="Group Chat Manager", ability_text="The Super Router spawns iterative loops — agents reviewing and correcting each other rather than acting once. When hired, each card played this round is evaluated twice (retrigger its scoring once). For each subsequent round Super Router remains hired, the retrigger count grows by +1 (round 2 = 2 retriggles, round 3 = 3, etc.). A team that keeps reviewing its own output improves over time.", rarity="Common", salary=5, groups={"agentic-ai-pioneers", "ai-engineer-wave"}, hint="retrigger + scaling-over-time", effect={type="retrigger", scaling="scaling_per_round", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="", ke_complement=false}, dsl={retrigger={base=1, coef=1, per="rounds_held"}}},
  {key="f_chris-malachowsky", effect_brief="Creates AI card: 1st Infra+AI hand", set="Founder", name="Silent Moat", short="Moat", ability_name="Abstraction Ships With Sili…", ability_text="The Silent Moat knew the silicon alone would never achieve platform adoption — the abstraction layer is the product. The first time you play a hand containing at least one Infra-layer card and at least one AI-layer card together, immediately add one random AI-layer tech card to your deck at no cost. Fires exactly once per run ('CUDA shipped') and then goes dormant: the new asset compounds independently of the hardware that spawned it.", rarity="Rare", salary=20, hint="one-time generation burst: add a random A…", effect={type="generation", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 random AI-layer tech card added to deck (one-time; trigge…", ke_complement=false}, dsl={hook="joker_main", ops={{k="gen", kind="tech_card", layer="AI", amount=1}}, gate={g="and", gs={{g="layer_present", layer="Infra"}, {g="layer_present", layer="AI"}}}, once=true, once_scope="run"}},
  {key="f_chris-olah", effect_brief="Dissolves clashes scaling with distinct Layers this run", set="Founder", name="Ghost Whisperer", short="Whisperer", ability_name="Circuit Dictionary", ability_text="The Ghost Whisperer reads the compatibility that the architecture already contains, waiting to be seen. As your stack broadens, more of its hidden interop reveals itself: each time you Ship, dissolve a number of compatibility clashes equal to half the distinct Layers you have adopted this run (rounded down). No +Users or +Rev — purely structural interop that scales with how broad your stack has grown.", rarity="Uncommon", salary=10, groups={"ex-openai-diaspora", "anthropic-founding-team"}, hint="permanently removes one compatibility cla…", effect={type="utility", scaling="scaling_persistent", hook="individual", primitive_hint=nil, engine_status="data_only", magnitude="1 clash removed per first-seen distinct tech card (cumulati…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", per="distinct_layers_seen_run", base=0, coef=0.5}}}},
  {key="f_christian-szegedy", effect_brief="+3 Rev/Layer if dupes played; +1/round", set="Founder", name="Panda Whisperer", short="Whisperer", ability_name="Adversarial Refactor", ability_text="The Panda Whisperer rewards breadth-by-factorization over naive depth-spamming — efficiency through parallel coverage, not redundancy. When you Ship a hand where any single tech card appears more than once, remove one duplicate from scoring but grant +3 Rev for every distinct Layer represented instead. Gains +1 Rev per round held as iterated architecture versions compound.", rarity="Uncommon", salary=10, groups={"xai-founding-team", "ex-google-brain"}, hint="conditional +Rev on efficiency (paramete…", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="redundant_cards", op=">", val=0}, ops={{k="scale", field="mult", coef=3, per="distinct_layers"}, {k="scale", field="mult", coef=1, per="rounds_held"}}}},
  {key="f_clay-bavor", effect_brief="+1 Rev per AI hand shipped, stacks", set="Founder", name="Flip-Flop Prophet", short="Prophet", ability_name="Supervisor Loop", ability_text="The Flip-Flop Prophet bets that the solution to bad AI is more AI — a supervisor loop that tightens each time it runs. Each Ship where at least one AI-layer card was played, gain +1 Rev permanently. Stacks quietly across the run, then explodes on a well-built AI-heavy stack: the rate climbs, not the headcount.", rarity="Common", salary=5, hint="plus_mult that grows permanently each tim…", effect={type="plus_mult", scaling="scaling_persistent", hook="after", primitive_hint="mult", engine_status="executable", magnitude="0 base; +1 mult per Ship in which any AI-layer card was pla…", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="plus_mult", when="post"}}, gate={g="layer_present", layer="AI"}}},
  {key="f_clayton-christensen", effect_brief="1st Ship of a new App Type: copy deck's cheapest card", set="Founder", name="Gentle Disruptor", short="Disruptor", ability_name="Attacker From Below", ability_text="The Gentle Disruptor enters from below — each new lane seeded cheaply becomes the base for the next climb. The first time each run you Ship under a distinct App Type you have not scored with before, add a permanent copy of the cheapest (lowest base Users) card in your deck.", rarity="Legendary", salary=40, hint="generation: each new distinct App Type yo…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="+1 lowest-base-Users card per newly-entered distinct App Ty…", ke_complement=false}, dsl={hook="after", ops={{k="gen", kind="copy_card", which="cheapest", per="new_app_types"}}}},
  {key="f_clement-delangue", effect_brief="+(Community×2) Users; +Comm Rev if AI", set="Founder", name="Open-Source Arsonist", short="Arsonist", ability_name="Open-Source Flywheel", ability_text="The Open-Source Arsonist turned radical openness into compounding gravity — the longer you commit to open infrastructure, the bigger the network-effect payoff. Each round this founder is held, +1 to a hidden Community counter. At Ship, gain +(Community × 2) Users. If the round's App Type touches the AI Layer, also gain +(Community) Rev. Community resets to 0 if this founder is sold.", rarity="Uncommon", salary=10, groups={"open-source-ai", "french-ai-founders"}, hint="scaling-over-time + community multiplier…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0, coef=2, state="comm", when="post", step="round", reset_on={"selling_self"}}, {k="acc", field="mult", base=0, coef=1, state="comm", when="post", step="round", reset_on={"selling_self"}, gate={g="layer_present", layer="AI"}}}}},
  {key="f_craig-newmark", effect_brief="-1 Salary/round, plus -0.5 more per round he's been hired", set="Founder", name="Delete-Key Baron", short="Baron", ability_name="Customer Service Rep", ability_text="The Delete-Key Baron shrank himself deliberately — skeleton crew, no upgrades, total commitment to the lane — and watched the product outlast every rival. While hired, your Salary overhead drops by 1 each round, and by a further 0.5 for every round he has been on the team. Patience compounds: the longer you keep the lights low, the less payroll you owe.", rarity="Common", salary=5, hint="Salary reduction + Margin boost via skele…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="salary", amount=1, per="rounds_held", coef=0.5}}}},
  {key="f_curtis-priem", effect_brief="+$1 Cash per Infra card played, stacks", set="Founder", name="Trillion-Dollar Ghost", short="Ghost", ability_name="Silent Endowment", ability_text="The Trillion-Dollar Ghost laid the architectural blueprint quietly and never sought the spotlight — invisible until you see the cumulative tab and realize it is paying everyone's Salary. Each time an Infra card is played across the run, permanently add $1 to this card's passive Cash payout (paid after each hand). Once you've played 40+ Infra cards it will comfortably cover a senior founder's running cost.", rarity="Uncommon", salary=10, hint="After each hand, permanently gain $1 per…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="1 * distinct_infra_cards_played_this_run (permanent, recalc…", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="dollars", base=0, coef=1, inc_per="cards_of_layer", layer="Infra", when="post", state="ghost_endow"}}}},
  {key="f_dan-bricklin", effect_brief="×3 Rev once: first 3-Layer hand", set="Founder", name="Father of the Cell", short="Cell", ability_name="Platform Ignition", ability_text="Father of the Cell shipped one product that touched enough of the stack to make businesses buy the entire platform just to run it — a killer-app ignition that happens exactly once. The first time in a run that a scored hand covers 3 or more distinct Layers, score ×3 Rev for that hand. Fires once per run and then goes dormant: the inflection point is unrepeatable, but the growth it unlocks compounds forever after.", rarity="Uncommon", salary=10, groups={"New England Apple Tree"}, hint="one-time xMult burst the first time you p…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="x3 (fires once per run, on the first hand with distinct_lay…", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=3.0, coef=0}}, gate={g="count", per="distinct_layers", op=">=", val=3}, once=true, once_scope="run"}},
  {key="f_daniel-de-freitas", effect_brief="+8 Rev once: first low-fit Market Ship", set="Founder", name="Blocked Prophet", short="Prophet", ability_name="Sundar Asked Me to Stay", ability_text="The establishment stamped BLOCKED on every attempt to ship something bold — so Blocked Prophet walked out the door instead. The first time you play an App Type into a Market with a low fit-score this run, gain +8 Rev for that hand. Fires once per run only: one decisive contrarian bet, one payoff.", rarity="Common", salary=5, groups={"ex-google-ai-diaspora"}, hint="+8 Rev one time when you first play an A…", effect={type="plus_mult", scaling="conditional_burst", hook="before", primitive_hint="mult", engine_status="executable", magnitude="+8 (once per run, triggers on first low-fit App Type play)", ke_complement=false}, dsl={hook="before", gate={g="market_fit", op="<", val=1}, ops={{k="scale", field="mult", base=8.0, coef=0}}, once=true, once_scope="run"}},
  {key="f_daniel-gross", effect_brief="Surplus ARR→+Margin; -1 Salary/Infra", set="Founder", name="Cluster Whisperer", short="Whisperer", ability_name="Compute Unlock", ability_text="While others argued about the waiting list, Cluster Whisperer was already installing the hardware himself. Whenever a Ship scores more ARR than the blind target requires, the surplus converts into a permanent +Margin bonus. Additionally, your Salary cost is reduced by 1 for each Infra-layer card in your deck — infrastructure becomes a moat, not a cost center.", rarity="Common", salary=5, groups={"ai-grant", "ex-openai-diaspora"}, hint="remove Salary drag / convert overkill ARR…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", gate={g="overkill", op=">", val=0}, ops={{k="grant", what="margin", per="overkill", coef=0.0008}}}},
  {key="f_daniela-amodei", effect_brief="1st blind-win/ante: +5% Margin, cap +15%", set="Founder", name="Safety Closer", short="Closer", ability_name="Safety as a Feature", ability_text="Safety Closer turns compliance from a cost centre into the premium feature enterprise buyers line up to pay for. The first blind you win each ante, raise your Margin by +5% permanently — stacking up to +15%.", rarity="Uncommon", salary=10, groups={"ex-openai-diaspora", "anthropic-founding-team", "ex-openai", "anthropic-founders"}, hint="Margin (raise) + conditional scaling over…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="blind_won", once=true, once_scope="ante", ops={{k="grant", what="margin", amount=0.05, max=0.15}}}},
  {key="f_dario-amodei", effect_brief="+×0.25 Rev per new Layer seen, stacks", set="Founder", name="Conscience Bomber", short="Bomber", ability_name="Predictable Performance Gai…", ability_text="Conscience Bomber saw the curve early and refused to look away: add enough stack depth and the gains become predictable. Each time you play a hand that introduces a Layer not previously seen this run, your ×Rev permanently ticks up by ×0.25. Five distinct Layers reached = ×2.25 total — the first new Layer is cheap to find; the fifth rewards a team that built the whole stack.", rarity="Rare", salary=20, groups={"ex-openai-diaspora", "anthropic-founding-team", "ex-openai", "anthropic-founders"}, hint="xMult grows permanently each time a new d…", effect={type="xmult", scaling="scaling_persistent", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.25 * distinct_layers_seen_this_run", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="x_mult", base=1.0, coef=0.25, per="distinct_layers_seen_run"}}}},
  {key="f_david-ferrucci", effect_brief="Distinct-Layer hand: x1.5 Rev (x2 with AI); else +8 Rev", set="Founder", name="Doctor Buzzkill", short="Buzzkill", ability_name="Confidence Threshold", ability_text="Doctor Buzzkill knows fluency without understanding is just a confident-sounding blank, so he checks the architecture before he believes the demo. When you Ship a hand where every played card is a distinct Layer (a real full-stack build, no shallow padding), it passes the confidence check: x1.5 Rev. If that clean build also includes an AI-Layer card, the burst jumps to x2.0 Rev. Any hand that fails the check doesn't crash, it just gets a guaranteed +8 Rev floor instead of the burst.", rarity="Uncommon", salary=10, groups={"ibm-watson-team", "neurosymbolic-ai-founders"}, hint="×Rev gated by hand quality + universal a…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.5, gate={g="and", gs={{g="all_distinct_layers"}, {g="not", g1={g="layer_present", layer="AI"}}}}}, {k="scale", field="x_mult", base=2.0, gate={g="and", gs={{g="all_distinct_layers"}, {g="layer_present", layer="AI"}}}}, {k="scale", field="mult", base=8, gate={g="not", g1={g="all_distinct_layers"}}}}}},
  {key="f_david-filo", effect_brief="+40 Users if hand scores 0 Users", set="Founder", name="Honest Bouncer", short="Bouncer", ability_name="Honest Dead End", ability_text="Honest Bouncer believed that a dead end handled with integrity was worth more than a flashy result — and wired the product to prove it. If the App Type classification fails to score any Users this hand, gain a one-time burst of +40 Users for that scoring pass (fires at most once per round). No burst fires on a hand that already scored Users; this rewards graceful failure, not padding a winning pipeline.", rarity="Common", salary=5, groups={"early-yahoo-team"}, hint="plus_chips — when a scored hand produces…", effect={type="plus_chips", scaling="conditional_burst", hook="after", primitive_hint="chips", engine_status="executable", magnitude="40 (once per round, triggered only when hand_users == 0)", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op="<=", val=0}, ops={{k="scale", field="chips", base=40.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_david-heinemeier-hansson", effect_brief="+0.05 Margin per unplayed card, building to a +0.20 moat", set="Founder", name="Calm Podium Finisher", short="Finisher", ability_name="Less Is More", ability_text="The Calm Podium Finisher turned every constraint into a moat — fewer features shipped, tighter product, higher take-rate. Each Ship, your Margin permanently rises by +0.05 for every card in your hand you chose NOT to play, building toward a hard +0.20 ceiling. Restraint compounds: the discipline you bank stays banked.", rarity="Uncommon", salary=10, hint="Margin + scaling-over-time", effect={type="economy", scaling="flat", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="grant", what="margin", per="unplayed_cards", coef=0.05, max=0.20}}}},
  {key="f_david-holz", effect_brief="+Users per lean hand, grows each ship", set="Founder", name="Sailboat Recluse", short="Recluse", ability_name="Revenue Per Headcount", ability_text="Sailboat Recluse twice declined the buyout and built his user base on word-of-mouth alone — staying lean was never restraint, it was the engine. While this founder is hired, every time you play a hand containing 3 or fewer tech cards, gain +5 Users permanently. A 1-card hand grants +12 instead. The fewer cards played, the larger the compounding bonus.", rarity="Common", salary=5, hint="Each hand played with 3 or fewer tech car…", effect={type="plus_chips", scaling="scaling_persistent", hook="after", primitive_hint="chips", engine_status="executable", magnitude="hand_size <= 3 ? (hand_size == 1 ? 12 : 5) : 0  [permanent,…", ke_complement=false}, dsl={hook="after", gate={g="count", per="hand_size", op="<=", val=3}, ops={{k="acc", field="chips", base=0, coef=5, state="recluse", step="ship", when="post"}}}},
  {key="f_david-luan", effect_brief="1st 3-Layer ship/ante adds tech cards", set="Founder", name="Ghost-Cursor Grinder", short="Grinder", ability_name="ACT-1 Threshold", ability_text="Ghost-Cursor Grinder held out until the stack was genuinely ready — then took everything at once. The first time each ante you Ship an App Type whose coverage spans 3 or more distinct Layers, add 1 random tech card from each covered Layer directly to your hand. Below the bar nothing fires; cross it once and the hand floods with the exact stack you just proved you could run.", rarity="Common", salary=5, groups={"ex-openai-mafia"}, mafia=true, hint="when you hit Ghost-Cursor Grinder's relia…", effect={type="generation", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 tech card per distinct Layer covered (min 3 Layers to tri…", ke_complement=false}, dsl={hook="after", once=true, once_scope="ante", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="gen", kind="tech_card", per="distinct_layers"}}}},
  {key="f_david-packard", effect_brief="End of Ship: −$1 Salary and +$1 Cash per other Founder", set="Founder", name="Open-Door Giant", short="Giant", ability_name="Open Storeroom", ability_text="Open-Door Giant kept the parts-bins unlocked and unstaffed — the trust itself was the policy, and it compounded. At the end of each Ship, your Salary is reduced by $1 for each other Founder you have hired, and you collect $1 Cash for each other Founder. The bigger the team you hold together, the cheaper and more productive it gets.", rarity="Rare", salary=20, hint="Salary reduction + team-wide scaling", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="salary", per="others", coef=1}, {k="grant", what="cash", per="others", coef=1}}}},
  {key="f_david-sacks", effect_brief="+1 Margin per redundant card on Ship (max +4/run)", set="Founder", name="Friction Killer", short="Killer", ability_name="Dr. No", ability_text="Friction Killer doesn't add features — he cuts fat. When you Ship, for each redundant card in the played hand (a tech that overlaps a Layer another played card already covers), gain +1 Margin permanently — up to +4 Margin per run. Redundancy gone, conversion climbs.", rarity="Uncommon", salary=10, groups={"paypal-mafia"}, mafia=true, hint="Margin (friction-cut → conversion rate li…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="grant", what="margin", per="redundant_cards", coef=1.0, max=4}}}},
  {key="f_david-silver", effect_brief="Retriggers each AI card floor(1+rounds_held/3)x", set="Founder", name="Honeymoon Heretic", short="Heretic", ability_name="Honeymoon Algorithm", ability_text="Honeymoon Heretic's cleanest insight arrived when he stepped away: no shortcuts, no inherited data — just experience replayed against itself. After scoring, each AI-layer card is re-scored floor(1 + rounds_held/3) additional times (minimum 1, climbing past 4 by late ante). The self-play loop deepens by +1 retrigger every third round this founder is held.", rarity="Uncommon", salary=10, groups={"deepmind-alumni", "deepmind-rl-team"}, hint="retrigger: the highest-Users AI-layer car…", effect={type="retrigger", scaling="scaling_per_round", hook="repetition", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="floor(1 + rounds_held / 3)", ke_complement=false}, dsl={ retrigger = { base = 1, coef = 1/3, per = "rounds_held" }, gate = { g = "card_layer", layer = "AI" } }},
  {key="f_dean-allemang", effect_brief="Ignores all compatibility clashes", set="Founder", name="Triple Threat", short="Threat", ability_name="The AAA Slogan", ability_text="Triple Threat spent decades proving that no data source needs to be excluded — any two systems can be linked if you give them a shared grammar. While this joker is in play, all compatibility clashes in your built hand are ignored: every Layer card interoperates with every other as if perfectly aligned, and no card's Users value is ever penalized for a mismatch.", rarity="Uncommon", salary=10, groups={"semantic-web-practitioners", "w3c-shacl-working-group", "edm-council-fibo-team"}, hint="Utility: nullifies all compatibility clas…", effect={type="utility", scaling="flat", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="clears all compatibility-clash penalties (flat, uncondition…", ke_complement=true}, dsl={hook="before", ops={{k="clear_clash", amount="all"}}}},
  {key="f_demis-hassabis", effect_brief="+0.25× per new Layer first touched (max ×2.25)", set="Founder", name="Move 37 Prophet", short="Prophet", ability_name="Transferable Architecture", ability_text="Move 37 Prophet never discards a domain — every field mastered becomes scaffolding that amplifies the next. The first time each run your shipped hand introduces a Layer not used before, his ×Rev permanently rises by +0.25 (starts at ×1, caps at ×2.25 once all 5 Layers are touched). The same architecture that cracked one impossible problem gets repurposed to crack the next.", rarity="Rare", salary=20, groups={"deepmind-founders", "deepmind-diaspora", "google-deepmind-leadership"}, hint="Permanent ×Rev snowball: every first-tim…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.25*distinct_layers_first_touched_this_run", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.25, per="distinct_layers_seen_run"}}}},
  {key="f_denis-yarats", effect_brief="Lean hand (<=3): retrigger top-Users card, reps=ante", set="Founder", name="Signal Augmenter", short="Augmenter", ability_name="Augment the Signal", ability_text="Signal Augmenter proved leaner input with smarter processing beats brute-force complexity. When you Ship a hand of 3 or fewer cards, the highest-Users card in that hand is retriggered (its Users counted again). The number of retriggers equals the current ante: 1 at pre-seed, growing each funding stage as compounding research depth makes the same lean discipline pay off harder over time.", rarity="Common", salary=5, groups={"ex-meta-ai", "ai-engineer-wave", "meta-fair-alumni", "nyu-phd"}, hint="+Users (retrigger) + scaling-over-time", effect={type="retrigger", scaling="scaling_persistent", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="", ke_complement=false}, dsl={retrigger={base=0, coef=1, per="ante"}, retrigger_target="highest", gate={g="count", per="hand_size", op="<=", val=3}}},
  {key="f_dick-costolo", effect_brief="+3 Users permanently each Ship", set="Founder", name="Yes-And Usurper", short="Usurper", ability_name="Feed the Firehose", ability_text="Yes-And Usurper built a syndication layer that turned one publish into thousands of simultaneous eyeballs — and then did it for a living. Each time you Ship a hand, your base User count grows permanently by +3 Users. The firehose widens with every play: modest early, compounding massively by late antes as the distributed reach stacks up.", rarity="Common", salary=5, groups={"Second City", "01 Advisors"}, hint="plus_chips: each Ship permanently adds +3…", effect={type="plus_chips", scaling="scaling_persistent", hook="after", primitive_hint="chips", engine_status="executable", magnitude="3 * ships_this_run", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="chips", base=0.0, coef=3, state="firehose", when="post"}}}},
  {key="f_dominik-lorenz", effect_brief="+3 Rev per card NOT played this hand", set="Founder", name="Latent Defector", short="Defector", ability_name="Latent Space", ability_text="Latent Defector's breakthrough: you don't need to work in full resolution — compress first, do the heavy lifting in a lean space, expand back out. Each card you choose NOT to play (below the hand size limit) adds +3 Rev to this round's score. A 2-card hand earns more Rev bonus than a 5-card hand — deliberate compression beats brute-force pile-ups.", rarity="Common", salary=5, groups={"compvis-group", "stable-diffusion-diaspora"}, hint="+Rev (conditional on compression / under…", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0, coef=3, per="unplayed_cards"}}}},
  {key="f_don-valentine", effect_brief="+Rev if Market fit; +4 Rev per Layer", set="Founder", name="One That Got Away", short="Away", ability_name="Aircraft Carrier Flotilla", ability_text="One That Got Away had one rule: only back a product that rides a large, pre-existing wave — never one that has to create the wave itself. When you Ship a hand whose App Type matches the active Market's primary lane, gain +8 Rev, plus +4 Rev for each distinct Layer your scoring cards cover. No Market fit, no burst.", rarity="Legendary", salary=40, hint="Big +Rev lump when your Ship rides the a…", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="market_lane_match ? 8 + 4*distinct_layers : 0", ke_complement=false}, dsl={hook="joker_main", gate={g="market_fit", op=">", val=1}, ops={{k="scale", field="mult", base=8, coef=4, per="distinct_layers"}}}},
  {key="f_douglas-chen", effect_brief="+8 Users perm each time Infra is played", set="Founder", name="Accidental Architect", short="Architect", ability_name="Overbuild the Foundation", ability_text="Accidental Architect over-engineered the foundation nobody could see — and woke up one morning to find it was the product. Each time you Ship a hand that includes at least one Infra card, gain +8 Users permanently. The moat grows silently; by late antes the stack underneath is moving faster than anyone can copy.", rarity="Common", salary=5, groups={"mit-alumni"}, hint="Permanently gain +Users each time the Inf…", effect={type="plus_chips", scaling="scaling_persistent", hook="after", primitive_hint="chips", engine_status="executable", magnitude="+8 chips permanently per Ship that contains ≥1 Infra-layer…", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="chips", base=0.0, coef=8, state="plus_chips", when="post"}}, gate={g="layer_present", layer="Infra"}}},
  {key="f_douglas-engelbart", effect_brief="×2 Rev first time each App Type is shipped", set="Founder", name="Mother of All Demos", short="Demos", ability_name="Mother of All Demos", ability_text="Mother of All Demos showed the world things it had no framework to understand — once, live, in ninety minutes, and then the horizon changed forever. The first time you Ship each App Type this run, score ×2 Rev for that hand. Each new App Type triggers it exactly once: the world has never seen this before, so the reaction is outsized. Pairs with founders who broaden your App-Type repertoire so there are more first demos to fire.", rarity="Rare", salary=20, hint="xMult burst the first time each distinct…", effect={type="xmult", scaling="conditional_burst", hook="individual", primitive_hint="x_mult", engine_status="executable", magnitude="x2 per first Ship of each distinct App Type (fires at most…", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="new_app_types", op=">=", val=1}, ops={{k="scale", field="x_mult", base=2.0, coef=0}}}},
  {key="f_douglas-lenat", effect_brief="Nullifies a clash per distinct Layer seen this run; no score", set="Founder", name="Common-Sense Mason", short="Mason", ability_name="Consensus Reality Substrate", ability_text="Common-Sense Mason argues there is no shortcut: you accumulate common sense one Layer at a time, and the broader your experience, the more incompatible techs you can make interoperate. Adds no score number. At scoring, nullifies one compatibility clash in your built hand for each distinct Layer you have ever shipped this run — fit penalties dissolve. Strictly better the longer the run and the more diverse your builds.", rarity="Legendary", salary=40, groups={"cyc-project", "mcc-ai-lab", "computers-and-thought-award-laureates"}, yc=true, hint="utility: a permanent common-sense layer t…", effect={type="utility", scaling="scaling_persistent", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="clash_nullifications = sum_over_ships(distinct_layers_in_ha…", ke_complement=true}, dsl={hook="before", ops={{k="clear_clash", per="distinct_layers_seen_run", base=0, coef=1}}}},
  {key="f_drew-houston", effect_brief="Solo founder: ×2 ×Rev, +0.2× per round held. Resets on sell.", set="Founder", name="Fake Ship Captain", short="Captain", ability_name="Hacker News Drop", ability_text="Fake Ship Captain knows distribution beats engineering. While he is your ONLY hired Founder, the referral loop fires: this hand's Rev-per-user is multiplied — ×2 ×Rev the first round, then +0.2× more for every consecutive round you go solo (the viral loop compounds the longer you ship lean and hire nobody). The streak resets the instant you sell any Founder.", rarity="Uncommon", salary=10, hint="viral Users (Users) spike + freemium conv…", effect={type="plus_chips", scaling="scaling_per_round", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="others", op="==", val=0}, ops={{k="acc", field="x_mult", base=2, coef=0.2, when="pre", step="round", reset_on={"selling_self","selling_card"}, max=15}}}},
  {key="f_dustin-moskovitz", effect_brief="Adds tech card to deck each round held", set="Founder", name="Ox Who Held", short="Held", ability_name="Campus by Campus", ability_text="The Ox Who Held earned his reputation proving a platform the hard way — one market at a time. Each round you hold him without playing him, he adds one random tech card drawn from a Layer already represented in your deck permanently. The deck quietly snowballs the longer he sits: patience over blitzscaling, stability over spectacle.", rarity="Uncommon", salary=10, groups={"facebook-founding-quartet", "kirkland-house-suite-h33"}, hint="permanently adds one tech card to the dec…", effect={type="generation", scaling="scaling_persistent", hook="held", primitive_hint=nil, engine_status="data_only", magnitude="1 tech card added per round held (drawn from a Layer alread…", ke_complement=false}, dsl={hook="blind_won", ops={{k="gen", kind="tech_card"}}}},
  {key="f_ed-catmull", effect_brief="+0.2× perm per first-time Layer covered", set="Founder", name="Wireframe Whisperer", short="Whisperer", ability_name="Render Pass", ability_text="Wireframe Whisperer knows that every great product begins as an ugly, broken thing — and improves only through honest iteration. Each time you Ship a hand covering at least one Layer you have never covered before in this run, gain +0.2× permanently to your Rev multiplier. The uglier the first pass, the more room there is to grow; by Ship 10 the compounding is irreversible.", rarity="Uncommon", salary=10, groups={"University of Utah"}, hint="xMult that grows permanently each time yo…", effect={type="xmult", scaling="scaling_persistent", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.2 * distinct_new_layers_shipped_lifetime", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="x_mult", base=1.0, coef=0.2, per="distinct_layers_seen_run"}}}},
  {key="f_edward-feigenbaum", effect_brief="×Rev grows per re-shipped App Type", set="Founder", name="Toy-Problem Tamer", short="Tamer", ability_name="The Knowledge Principle", ability_text="Toy-Problem Tamer built his reputation on a simple conviction: a program's power lives in its knowledge base, not its inference engine. While in play, every built Layer card gains a small flat +Users bonus. His headline effect: a growing KNOWLEDGE BASE counter gains +1 each time you Ship an App Type you have already shipped this run, and your final score is multiplied by ×Rev equal to 1.0 + 0.2× per knowledge point. Reshippping the same narrow domain compounds hard; pivoting to a brand-new App Type adds nothing that round.", rarity="Rare", salary=20, groups={"stanford-ai-founders", "dendral-team", "turing-award-laureates"}, hint="Universal +Rev that scales with accumula…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", gate={g="count", per="new_app_types", op="==", val=0}, ops={{k="acc", field="x_mult", base=1.0, coef=0.2, state="knowledge", when="post", step="ship", max=20}}}},
  {key="f_edwin-land", effect_brief="×Layers burst on first Boss Blind 4+ Layers", set="Founder", name="One-Hour Oracle", short="Oracle", ability_name="Nearly Impossible Threshold", ability_text="One-Hour Oracle set one rule for himself: only pursue goals that are manifestly important and nearly impossible. When you clear a Boss Blind for the first time in a run and the scoring hand spans 4 or more distinct Layers, fire a one-time ×(distinct_layers_in_hand) Rev burst — x4 or x5 at maximum. The image resolves once. The burst never repeats.", rarity="Rare", salary=20, hint="xmult — one-time burst: when you clear th…", effect={type="xmult", scaling="conditional_burst", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="x(distinct_layers_in_hand) when distinct_layers_in_hand >=…", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="x_mult", base=0.0, coef=1.0, per="distinct_layers"}}, gate={g="and", gs={{g="is_boss_blind"}, {g="count", per="distinct_layers", op=">=", val=4}}}, once=true, once_scope="run"}},
  {key="f_elizabeth-holmes", effect_brief="+×0.15 Rev per funding stage reached; permanent snowball", set="Founder", name="Vial Visionary", short="Visionary", ability_name="Hundred Votes Per Share", ability_text="Vial Visionary's narrative compounds when nothing checks it. For every funding stage (Ante) you reach, her ×Rev rises by ×0.15 permanently — the story snowballs with each round of unopposed progress. ×1.0 at pre-seed, ×1.6 by Series B, ×2.05 at IPO. Slow but relentless — until the market finally audits the books.", rarity="Uncommon", salary=10, hint="xMult grows permanently each blind you wi…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.15 * blinds_won", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=0.85, coef=0.15, per="ante"}}}},
  {key="f_elon-musk", effect_brief="+Margin per delete; ×Rev if <60% hand", set="Founder", name="Plug-Puller", short="Plug-Puller", ability_name="The Idiot Index", ability_text="Plug-Puller runs on a five-step rule: question everything, delete the part, simplify, accelerate, automate. When in play you may DELETE one Layer card from your built hand each Ship; doing so raises Margin so more of your ARR converts to Cash, and the smaller hand scores at ×Rev instead of +Users. Deleting more than ~40% of your starting hand size triggers an over-deletion penalty — lose a portion of the round's ARR. If you don't end up reinstating some of what you cut, you didn't cut enough.", rarity="Legendary", salary=40, groups={"paypal-mafia", "tesla-cofounders", "openai-founders", "xai-founding-team"}, mafia=true, hint="Margin (cost-cutting via deletion) + over…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="delete_card", margin=0.16, overcut=3}, {k="scale", field="x_mult", base=1, coef=0.10, per="redundant_cards"}}}},
  {key="f_emad-mostaque", effect_brief="Ship: +60 Users, then 50/50 x2 or x0.75 Rev (x4 after 3 misses)", set="Founder", name="Open-Source Prophet", short="Prophet", ability_name="Open-Source Drop", ability_text="Open-Source Prophet drops the model in public and rides whatever wave comes. When you Ship, gain +60 Users, then flip the viral wave: a hit gives x2 Rev and a fizzle cuts Rev to x0.75. After three straight fizzles, the next drop is guaranteed to go megaviral for x4 Rev.", rarity="Common", salary=5, hint="+Users (Users spike) with conditional cre…", effect={type="plus_chips", scaling="flat", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="chips", base=60, coef=0}, {k="gamble", p=0.5, win=2, lose=0.75, n=3, guaranteed=4, state="opensource"}}}},
  {key="f_eric-ries", effect_brief="Suppresses 1 Layer clash/round, +1 Layer/round", set="Founder", name="Embarrassing MVP", short="MVP", ability_name="Fifty Deploys a Day", ability_text="Embarrassing MVP pioneered the discipline of shipping something broken before you fall in love with it. When held in the joker slot, at the start of each round he validates one Layer, cycling Frontend → Backend → Data → Infra → AI, then repeating. Compatibility clashes from that Layer are suppressed for the rest of the round — those cards score as if fully compatible regardless of Market or stack mismatch. After R rounds held he covers R distinct Layers simultaneously (cap: all 5).", rarity="Uncommon", salary=10, groups={"lean-startup-movement"}, hint="utility: each round held, neutralizes one…", effect={type="utility", scaling="scaling_per_round", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="min(rounds_held, 5) Layers have clashes suppressed; cycles…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", per="rounds_held", base=0, coef=1}}}},
  {key="f_eugene-kleiner", effect_brief="+$2+$1/ante paid on each blind win", set="Founder", name="Calm Letter Writer", short="Writer", ability_name="Speculative Vintage", ability_text="Calm Letter Writer is in the business of making highly speculative investments — and he names the risk rather than hiding it. At the end of every blind you win, Calm Letter Writer pays out $2 + $1 for each ante you have completed so far. The dividend is small early and large late: patient capital pressed into speculative territory that returns multiples only to those who hold through the risk.", rarity="Rare", salary=20, groups={"traitorous-eight"}, hint="generates a permanent per-blind cash divi…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="2 + 1*antes_completed", ke_complement=false}, dsl={hook="blind_won", ops={{k="grant", what="cash", amount=2.0, per="ante", coef=1.0}}}},
  {key="f_evan-williams", effect_brief="-1 hand size; large +Rev per shipped card", set="Founder", name="Last Sysadmin", short="Sysadmin", ability_name="Push-Button Publishing", ability_text="Last Sysadmin knows that adding constraints forces clarity and wins the user. While in play your hand size is reduced by 1, but every shipped card gains a large +Rev bonus — the fewer techs you ship, the bigger the per-card payoff. Constraint becomes the multiplier: thin, focused App Types thrive; wide full-stack hands fight against him.", rarity="Uncommon", salary=10, groups={"twitter-cofounders", "twitter-founders"}, hint="Revenue-per-user (Rev) via a Coverage/ha…", effect={type="plus_mult", scaling="flat", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="individual", ops={{k="scale", field="mult", base=4, coef=3, per="unplayed_cards"}}, passive={what="hand_size", amount=-1}}},
  {key="f_fei-fei-li", effect_brief="+×0.3 per new Layer in deck (max ×2.5)", set="Founder", name="Dataset Oracle", short="Oracle", ability_name="Breadth Is the Bottleneck", ability_text="Dataset Oracle made the contrarian bet that coverage across categories — not algorithmic cleverness in one domain — was the real compounding unlock. When hired, she starts at ×1.0 Rev. Each time a new distinct tech Layer (Frontend, Backend, Data, Infra, AI) enters your deck for the first time — through the shop, a pack, or any card-gain event — her multiplier permanently increases by ×0.3. Maximum five stacks; a full five-Layer deck yields ×2.5 total.", rarity="Rare", salary=20, hint="xmult that grows permanently each time yo…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.3 * distinct_layers_ever_added", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.3, per="distinct_layers_seen_run"}}}},
  {key="f_frederick-brooks", effect_brief="Solo: +8 Rev. Else -12 Users per other Founder", set="Founder", name="Gasoline Prophet", short="Prophet", ability_name="Gasoline Prophet's Law", ability_text="Gasoline Prophet identified the law that haunts every growing team: communication overhead grows with headcount. Ship with exactly ONE Founder active (Gasoline Prophet alone) and the whole product comes from one undiluted mind — gain a flat +8 Rev that hand. But for every OTHER Founder on your roster, the coordination tax bites: each costs you 12 Users when you Ship. Adding people to a project makes it later.", rarity="Uncommon", salary=10, hint="team-size → Salary scaling (inverse)", effect={type="plus_mult", scaling="flat", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=8, coef=0, gate={g="count", per="others", op="==", val=0}}, {k="scale", field="chips", base=0, coef=-12, per="others", gate={g="count", per="others", op=">=", val=1}}}}},
  {key="f_gabriel-pereyra", effect_brief="+86 Users if all cards same Layer (1/round)", set="Founder", name="86-of-100 Kid", short="Kid", ability_name="86 of 100 Approved", ability_text="86-of-100 Kid built his proof the hard way: go deep in one domain and make the result undeniable. If you play a hand whose cards all belong to a single Layer (pure depth, no cross-stack noise), gain +86 Users immediately. Fires at most once per round. Spreading across Layers dilutes the spike away — staying in your lane and going deep earns it.", rarity="Common", salary=5, hint="plus_chips burst — when you play a hand t…", effect={type="plus_chips", scaling="conditional_burst", hook="individual", primitive_hint="chips", engine_status="executable", magnitude="86 if distinct_layers_in_hand == 1 else 0", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="distinct_layers", op="==", val=1}, ops={{k="scale", field="chips", base=86.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_geoffrey-hinton", effect_brief="+×0.15 per AI-multi-tech Ship, grows", set="Founder", name="Kneeling Kingmaker", short="Kingmaker", ability_name="Dark Age Compounding", ability_text="Kneeling Kingmaker spent decades building something the field said was a dead end — then watched it make every competing paradigm obsolete overnight. Each time you Ship a hand that includes cards from 2 or more distinct AI-layer techs, his xMult increases by ×0.15 permanently. The effect is invisible and slow to start — then suddenly enormous. Pairs strongest with his diaspora: graduates who built the modern AI industry stack up the compounding together.", rarity="Legendary", salary=40, groups={"hinton-diaspora", "toronto-ai-cluster", "godfathers-of-deep-learning"}, hint="xmult that grows permanently each time yo…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.15 * deep_ai_hands_played", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="cards_of_layer", layer="AI", op=">=", val=2}, ops={{k="acc", field="x_mult", base=1.0, coef=0.15, state="xmult", when="post", max=26}}}},
  {key="f_georges-doriot", effect_brief="Conviction+1/round; 2×overkill → Cash×Conviction", set="Founder", name="Patient General", short="General", ability_name="Patient Capital", ability_text="Patient General knew that one grand-slam bet, held patiently, beats a hundred hedges. Each round held without being sold increments a hidden Conviction counter (+1 per round). When you Ship and your ARR exceeds the blind target by 2× or more, convert the excess ARR into Cash equal to Conviction × $4. At Conviction 5+ the multiplier doubles permanently — unremarkable early, then one historic payday dwarfing everything else.", rarity="Uncommon", salary=10, hint="Scaling-over-time (grows each round held)…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}, ops={{k="scale", field="dollars", base=0, coef=4, per="rounds_held"}}}},
  {key="f_georgi-gerganov", effect_brief="Pure AI+Infra Ship (once/run): -$2 Salary per AI/Infra card", set="Founder", name="One-Weekend Runtime", short="Runtime", ability_name="Zero-Dependency Weekend", ability_text="Zero-Dependency Weekend: you proved in one commit you never needed the GPU cluster. The first time you Ship a hand built entirely of AI-layer and/or Infra-layer cards, permanently cut your payroll Salary by $2 for every AI or Infra card in that hand — the cloud bill evaporates. Fires exactly once per run, so the timing of when you assemble the pure-stack hand is a real decision.", rarity="Uncommon", salary=10, hint="One-time burst economy: first time you Sh…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="-$2 Salary per AI+Infra Founder held (fires once per run, o…", ke_complement=false}, dsl={hook="after", gate={g="and", gs={ {g="not", g1={g="layer_present", layer="Frontend"}}, {g="not", g1={g="layer_present", layer="Backend"}}, {g="not", g1={g="layer_present", layer="Data"}}, {g="or", gs={ {g="layer_present", layer="AI"}, {g="layer_present", layer="Infra"} }} }}, ops={ {k="grant", what="salary", per="cards_of_layer", layer="AI", coef=2}, {k="grant", what="salary", per="cards_of_layer", layer="Infra", coef=2} }, once=true, once_scope="run"}},
  {key="f_gordon-moore", effect_brief="×Rev +0.2/round shipped; resets on loss", set="Founder", name="Doubling Prophet", short="Prophet", ability_name="Doubling Curve", ability_text="Doubling Prophet noticed a local trend on graph paper and watched the entire industry organize its roadmaps around it. While in play, your Revenue-per-user multiplier compounds each round you Ship: ×1.3 in the first round, ×1.5 in the second, ×1.7 in the third, and so on. The counter resets on a lost blind but Doubling Prophet stays — the curve restarts, never disappears.", rarity="Rare", salary=20, groups={"intel-trinity", "traitorous-eight", "fairchildren"}, hint="xmult that grows each round held — starts…", effect={type="xmult", scaling="scaling_per_round", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.3 + 0.2 * (rounds_held - 1)", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.1, coef=0.2, state="xmult", when="post", step="ship", reset_on={"blind_lost"}, max=19}}}},
  {key="f_greg-brockman", effect_brief="+$8 on first 3-Layer Ship per ante", set="Founder", name="Loyal Bear", short="Bear", ability_name="Sabbatical Dividend", ability_text="Loyal Bear builds in focused bursts, then returns with the budget unlocked. The first time each ante you play a hand covering 3 or more distinct tech Layers, immediately gain $8. The trigger fires only once per ante — the builder hibernates, then wakes and commits the infrastructure tranche. Layer-breadth rewards full-stack Ships; the same cross-disciplinary range that lets him hack an entire API in a single weekend.", rarity="Rare", salary=20, groups={"openai-founders"}, hint="gain $8 once per ante when a Ship spans 3…", effect={type="economy", scaling="conditional_burst", hook="joker_main", primitive_hint="dollars", engine_status="executable", magnitude="$8 (once per ante, trigger: distinct_layers_in_hand >= 3)", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="grant", what="cash", amount=8}}, once=true, once_scope="ante"}},
  {key="f_greg-yang", effect_brief="Per-App-Type +Rev, +1/re-Ship; -1 Cash payroll/round", set="Founder", name="Seven-Percent Sage", short="Sage", ability_name="Zero-Shot Transfer", ability_text="Seven-Percent Sage found that settings tuned on a small model transfer perfectly to a giant — tune once, scale for free. Each App Type you Ship banks its own +Rev bonus that starts at +3 Rev and grows +1 Rev every later time you Ship that same App Type. While he is active, payroll is reduced by 1 Cash each round.", rarity="Common", salary=5, groups={"xai-founding-team", "ex-microsoft-research"}, hint="scaling-over-time + conditional cost redu…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=2.0, coef=1.0, state="zst", key="scoring_name", step="ship", when="post"}}, passive={what="salary", amount=1}}},
  {key="f_guillaume-lample", effect_brief="Ship AI: add free AI tech cards, +1 per AI card shipped", set="Founder", name="Blueprint Deserter", short="Deserter", ability_name="The Exodus Paper", ability_text="When you Ship a hand containing at least one AI-layer card, add 1 free AI-layer tech card to your deck, plus 1 more for each AI card in that hand. Publish everything, then walk out the door — the more AI you ship, the more tools follow you out.", rarity="Uncommon", salary=10, groups={"ecole-polytechnique-alumni", "french-ai-founders", "ex-meta-ai", "ex-meta-llama-team", "french-ai-ecosystem"}, hint="generation (scaling_persistent): each Shi…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 Founder card per Ship trigger; upgrade threshold = 3 trig…", ke_complement=false}, dsl={ hook="after", gate={ g="layer_present", layer="AI" }, ops={ { k="gen", kind="tech_card", layer="AI", per="cards_of_layer", base=1, coef=1 } } }},
  {key="f_harrison-chase", effect_brief="1st Ship/Layer: adds that Layer's card to deck", set="Founder", name="Back-Row Shipper", short="Shipper", ability_name="Nine-Day Package", ability_text="Back-Row Shipper built his framework in nine days by recognising that every developer was writing the same glue code — the moment he spots a new integration pattern he codifies it and ships it. The first time each distinct Layer appears in a played hand this run, immediately generate and add one tech card of that Layer into your deck permanently. By mid-run you're swimming in components he packaged for you, each one a future combo piece.", rarity="Uncommon", salary=10, groups={"ai-engineer-wave", "ex-robust-intelligence"}, hint="each newly seen Layer permanently adds a…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 tech card per newly seen Layer (max 5 cards, one per Laye…", ke_complement=false}, dsl={hook="after", ops={{k="gen", kind="tech_card", per="new_layers", base=0, coef=1}}}},
  {key="f_henry-ford", effect_brief="+1 Margin per distinct Layer scored (max +5)", set="Founder", name="Five-Dollar Prophet", short="Prophet", ability_name="Vertical Integration", ability_text="Five-Dollar Prophet ran the numbers and won the argument before anyone else understood the question. For each distinct Layer represented among the cards scored this round, gain +1 Margin (stacks, max +5). The more of the stack you own end-to-end, the less each unit costs to ship — a bootstrap flywheel that turns breadth-of-stack into operating leverage rather than raw ARR.", rarity="Rare", salary=20, hint="Margin (raised by in-house throughput sta…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="grant", what="margin", per="distinct_layers", coef=0.04}}}},
  {key="f_herbert-boyer", effect_brief="Full-spread Ship: splice 2 copies of top-User tech (1/blind)", set="Founder", name="Bead Whisperer", short="Whisperer", ability_name="Sticky-End Splice", ability_text="Bead Whisperer made recombination look like magic. When you Ship a full-recombination hand (every played tech is a distinct Layer), once per blind: 2 copies of your highest-User tech card are spliced into your draw pile. Build the clean full spread and your best tech suddenly multiplies.", rarity="Uncommon", salary=10, hint="generation — once per blind, inserts copi…", effect={type="generation", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="2 copies of highest-chip tech card in the played hand, trig…", ke_complement=false}, dsl={hook="after", gate={g="all_distinct_layers"}, once=true, once_scope="blind", ops={{k="gen", kind="copy_card", which="highest"}, {k="gen", kind="copy_card", which="highest"}}}},
  {key="f_herbert-simon", effect_brief="Removes all compatibility clashes in hand", set="Founder", name="Thinking-Machine Showman", short="Showman", ability_name="Difference Reduction", ability_text="Thinking-Machine Showman proved that every problem is just a difference waiting to be reduced. While in play, his General Problem Solver runs means-ends analysis on your whole stack — all Compatibility clashes in your built hand are removed and any Layer interoperates with any other (no off-stack penalties, the compatibility graph always resolves in your favor). Adds no Users or Revenue himself and is never counted in Coverage, but lets any deck — especially a wild full-stack one — play as if every piece were designed to fit.", rarity="Rare", salary=20, groups={"carnegie-mellon-ai-founders", "physical-symbol-system-school"}, hint="Universal complement: dissolves all cross…", effect={type="utility", scaling="flat", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="clears all cross-layer compatibility clashes (flat, uncondi…", ke_complement=true}, dsl={hook="before", ops={{k="clear_clash", amount="all"}}}},
  {key="f_holden-karnofsky", effect_brief="-1 Salary/2 founders; overkill ARR → 50% Cash", set="Founder", name="Astroturf Altruist", short="Altruist", ability_name="Responsible Scaling Policy", ability_text="Astroturf Altruist built a career on radical transparency — which makes the irony of his most notorious moment delicious. While hired, your Salary costs are reduced by 1 for every 2 Founders in play. Additionally, on any round where your ARR would exceed the current Ante's blind target by 2× or more, that overkill ARR is not lost — instead half converts directly to Cash, representing the civilizational leverage that comes from over-building at the right moment rather than racing past it blind.", rarity="Common", salary=5, groups={"ea-network", "amodei-family"}, hint="Salary (cost control) + conditional ARR s…", effect={type="economy", scaling="flat", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="salary", per="others", coef=0.5}, {k="grant", what="cash", per="overkill", coef=0.5}}}},
  {key="f_howard-schultz", effect_brief="+2 Rev per distinct Layer played (max +10)", set="Founder", name="Third Place Prophet", short="Prophet", ability_name="Third Place Premium", ability_text="Third Place Prophet understood that the best products sell belonging as much as they sell a feature. For each distinct Layer represented among the cards played this round, gain +2 Rev (stacks, max +10). Brand premium compounds when you offer a complete, multi-dimensional product experience — the more you cover, the stronger the emotional moat.", rarity="Common", salary=5, hint="+Rev scaling with Coverage (distinct Lay…", effect={type="plus_mult", scaling="flat", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0, coef=2, per="distinct_layers"}}}},
  {key="f_igor-babuschkin", effect_brief="+10/+20/+40 Users rounds 1-3 after hire", set="Founder", name="120-Day Engineer", short="Engineer", ability_name="Impossible Timeline", ability_text="120-Day Engineer operates on one principle: a maniacal sense of urgency can compress timelines the world has never seen. For the first 3 rounds after he is hired, each Ship action triggers an escalating Users bonus: +10 Users round 1, +20 round 2, +40 round 3. After round 3 the bonus resets; it can only fire once per run unless he is fired and rehired.", rarity="Common", salary=5, groups={"ex-deepmind", "ex-openai", "xai-founding-team"}, hint="+Users (Users), scaling-over-time per Ship", effect={type="plus_chips", scaling="conditional_burst", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="rounds_held", op="<", val=3}, ops={{k="scale", field="chips", base=10, coef=15, per="rounds_held"}}}},
  {key="f_ikujiro-nonaka", effect_brief="×Rev = layers×0.3 per Ship; layers grow", set="Founder", name="Bread Prophet", short="Prophet", ability_name="The SECI Spiral", ability_text="Bread Prophet proved competitive advantage compounds when tacit know-how is continuously converted into explicit knowledge and back again at ever-higher levels. At the start of each Blind, count the number of distinct Layers present across all hired Founders and played tech cards — this is your 'ba depth'. Each Ship action triggers one full conversion cycle: gain a ×Rev bonus equal to ba depth × 0.3 (3 layers = ×0.9, 5 layers = ×1.5). The bonus resets each round but ba depth is cumulative — adding a new Layer permanently upgrades the spiral for the rest of the run.", rarity="Uncommon", salary=10, groups={"knowledge-management-pioneers", "japanese-management-theorists"}, hint="×Rev scaling with stack diversity (layer…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=0, coef=0.3, per="distinct_layers_seen_run"}}}},
  {key="f_illia-polosukhin", effect_brief="+1 hand size; debut a new Layer -> clear 1 clash that Ship", set="Founder", name="Eighth Rail", short="Rail", ability_name="Agent Settlement Layer", ability_text="Eighth Rail builds for tracks nobody else thought were necessary, patient enough to look wrong for years while compounding the groundwork. While hired, hand size +1. The first time each Ship you play a tech card from a Layer you have not used before this run, one compatibility clash in that hand is smoothed away. No Rev — pure infrastructure.", rarity="Uncommon", salary=10, groups={"transformer-eight", "ex-google-ai-diaspora"}, hint="permanently removes one compatibility cla…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 clash removed per new Layer first played (max 5 over run)…", ke_complement=false}, dsl={hook="before", gate={g="count", per="new_layers", op=">=", val=1}, ops={{k="clear_clash", amount=1}}, passive={what="hand_size", amount=1}}},
  {key="f_ilya-sutskever", effect_brief="×3 Rev once if ARR >140% target", set="Founder", name="Quiet Singularity", short="Singularity", ability_name="15.3 vs 26.2", ability_text="Quiet Singularity holds conviction in silence until one decisive moment shatters the field's expectations. When you Ship and the hand's raw ARR exceeds the current blind's target by 40% or more, trigger 'Stunned the Field': multiply total Rev by ×3 for that score — once per run. The ability fires exactly once, like each of his era-defining bets.", rarity="Rare", salary=20, groups={"openai-founding-team", "godfathers-of-deep-learning", "openai-founders", "ex-openai-diaspora"}, hint="xmult conditional burst: once per run, wh…", effect={type="xmult", scaling="conditional_burst", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="x3 if (raw_ARR / blind_target) >= 1.40, once per run", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=1.40}, ops={{k="scale", field="x_mult", base=3.0, coef=0}}, once=true, once_scope="run"}},
  {key="f_ivan-zhang", effect_brief="+5% Margin if ≤3 layers; +1 Rev/round", set="Founder", name="Constraint Whisperer", short="Whisperer", ability_name="Constrained Deployment", ability_text="Constraint Whisperer turned the limits his customers imposed into his sharpest competitive edge. When you play an App Type using 3 or fewer distinct Layers, Margin increases by +5%. Additionally, each consecutive round you hold this founder, gain +1 Rev permanently — the data feedback loop compounds over time. The two effects stack: lean builds compound faster.", rarity="Common", salary=5, groups={"toronto-ai-cluster"}, hint="Margin (raise) + scaling-over-time (feedb…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0.0, coef=1.0, per="rounds_held"}, {k="grant", what="margin", amount=0.05, gate={g="count", per="distinct_layers", op="<=", val=3}}}}},
  {key="f_j-presper-eckert", effect_brief="+3 Rev/round if ARR lands ±10% target", set="Founder", name="Pulse Keeper", short="Keeper", ability_name="Mercury Delay Line", ability_text="Pulse Keeper believed that precision, not raw power, is the real competitive moat. Each round this founder is held, track how close your scored ARR lands to the blind target (within ±10%). On a 'precision hit' — ARR within that window — gain +3 Rev permanently (stacks). Miss wide (overkill or undershoot), gain nothing. Each precise pulse reinforces the next, building durable gain from transient signal.", rarity="Uncommon", salary=10, hint="scaling-over-time (precision dividend) +…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="and", gs={{g="arr_ratio", stage="pre_after", op=">=", val=0.9}, {g="arr_ratio", stage="pre_after", op="<=", val=1.1}}}, ops={{k="acc", field="mult", base=0, coef=3, state="precision", when="post", step="round"}}}},
  {key="f_jack-clark", effect_brief="+6 Rev on first hand of each Boss Blind", set="Founder", name="Briefing Room", short="Room", ability_name="Briefed Before It Breaks", ability_text="Briefing Room spent years teaching people how to think about risk — so by the time a crisis lands, his network has already been briefed. When the player enters a Boss Blind, grant +6 Rev for the first scored hand of that Blind only. Outside Boss Blinds the card is inert — his edge is specifically about anticipating systemic shocks, not grinding routine rounds.", rarity="Common", salary=5, groups={"ex-openai-diaspora", "anthropic-founding-team"}, hint="when entering a Boss Blind, gain +6 Rev…", effect={type="plus_mult", scaling="conditional_burst", hook="before", primitive_hint="mult", engine_status="executable", magnitude="+6 (first hand of Boss Blind only)", ke_complement=false}, dsl={hook="before", gate={g="is_boss_blind"}, ops={{k="scale", field="mult", base=6.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_jack-dorsey", effect_brief="×2.5 Rev if hand is 1–3 cards", set="Founder", name="Origami Monk", short="Monk", ability_name="Origami Crane Constraint", ability_text="Origami Monk's genius lives in the box, not outside it. When you Ship an App of exactly 1–3 cards, Rev is multiplied by ×2.5 for that scoring. Play more than 3 and nothing fires — the crane stays folded, unplaced. The burst is the payoff for discipline: it only lands when you hold back.", rarity="Uncommon", salary=10, groups={"twitter-cofounders", "Odeo crew"}, hint="xmult burst — when you Ship inside the co…", effect={type="xmult", scaling="conditional_burst", hook="individual", primitive_hint="x_mult", engine_status="executable", magnitude="if played_cards <= 3: x_mult * 2.5", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="hand_size", op="<=", val=3}, ops={{k="scale", field="x_mult", base=2.5, coef=0}}}},
  {key="f_jack-ma", effect_brief="From Stage 3: permanent +×0.15 Rev each Ship, forever", set="Founder", name="Noodle Dealer", short="Dealer", ability_name="Customers First", ability_text="Customers first, employees second, shareholders third — and a horizon long enough to make short-term pressure irrelevant. The Noodle Dealer sits quiet through the early stages. From Stage 3 onward, every Ship grows this card's multiplier permanently by ×0.15 (once per Ship), and it never resets. Hold him through the long climb and the patient compounding turns a noodle stall into an empire — by the late game his ×Rev dwarfs anything the impatient ever built.", rarity="Rare", salary=20, hint="scaling-over-time + Margin raise conditio…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.0, coef=0.15, state="tenure", step="ship", when="post", gate={g="ante", op=">=", val=3}, max=26}}}},
  {key="f_jacob-jackson", effect_brief="+40 Users once/blind if 3+ layers played", set="Founder", name="Ghost-Text Kid", short="Kid", ability_name="Draws From Context", ability_text="Ghost-Text Kid bet that a model with enough context stops guessing and starts knowing. The first time in a blind that you play a hand touching 3 or more distinct tech Layers, fire a burst of +40 Users (Users) that hand. Less coverage means still guessing; a broad stack means the answer was already in there. One burst per blind.", rarity="Common", salary=5, groups={"ioi-alumni"}, hint="+Users one-time burst when played hand sp…", effect={type="plus_chips", scaling="conditional_burst", hook="individual", primitive_hint="chips", engine_status="executable", magnitude="40 (fires once per blind when distinct_layers_in_hand >= 3)", ke_complement=false}, dsl={hook="individual", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="scale", field="chips", base=40.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_james-hendler", effect_brief="Clears all clashes; +0.5× per distinct layer", set="Founder", name="Web Weaver", short="Weaver", ability_name="The Ontology Aligner", ability_text="Web Weaver spent his career getting incompatible things to understand each other. While this joker is in play, ALL Layer cards in your built hand are treated as mutually compatible — every pairwise compatibility mismatch is resolved as if it were a perfect fit, so a scattered, ill-matched stack still earns its full Users. On top of that, grant ×Rev that scales with the diversity of distinct Layers in your hand: +0.5× Rev for each distinct Layer present (max +2.5× at a full 5-Layer build). The more different your techs, the harder he makes them sing together.", rarity="Rare", salary=20, groups={"semantic-web-founders", "w3c-webont-working-group", "darpa-program-managers"}, hint="Compatibility (interoperability) + divers…", effect={type="utility", scaling="flat", hook="joker_main", primitive_hint=nil, engine_status="data_only", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="clear_clash", amount="all"}, {k="scale", field="x_mult", base=1, coef=0.5, per="distinct_layers"}}}},
  {key="f_jan-koum", effect_brief="+12 Rev if single-layer hand", set="Founder", name="Food-Stamp Billionaire", short="Billionaire", ability_name="No Ads, No Games, No Gimmic…", ability_text="Food-Stamp Billionaire lived by one Post-It: no ads, no games, no gimmicks. When you Ship a hand whose tech cards all belong to a single Layer (no mixing), gain +12 Rev for that scoring. A single-Layer hand is the equivalent of a product that does exactly one thing and refuses to be anything else — the same discipline that let a tiny team serve hundreds of millions of users.", rarity="Uncommon", salary=10, hint="plus_mult spike when the played hand cont…", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="+12 mult if all scored cards share exactly one Layer", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=12.0, coef=0}}, gate={g="count", per="distinct_layers", op="==", val=1}}},
  {key="f_jared-kaplan", effect_brief="×1.5 Rev per layer beyond 2; once/blind", set="Founder", name="Scaling Seer", short="Seer", ability_name="Power-Law Exponent", ability_text="Scaling Seer watched chaos resolve into law across seven orders of magnitude and understood that the bigger the surface you cover, the more the curve snaps into focus. The first time in each blind that the played hand covers 3 or more distinct Layers, multiply Rev by ×1.5 per distinct Layer covered beyond 2 (×1.5 at 3 Layers, ×3.0 at 4, ×4.5 at 5). Fires once per blind only — you cannot have the epiphany twice in the same context.", rarity="Rare", salary=20, groups={"ex-openai-diaspora", "anthropic-founding-team"}, hint="xmult burst the first time a played hand…", effect={type="xmult", scaling="conditional_burst", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="1.5 * max(0, distinct_layers_in_hand - 2) if not already_fi…", ke_complement=false}, dsl={hook="after", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="scale", field="x_mult", base=-3.0, coef=1.5, per="distinct_layers"}}, once=true, once_scope="blind"}},
  {key="f_jb-straubel", effect_brief="+Cash & +1% Margin on 2× overkill", set="Founder", name="Robot-Slayer Recycler", short="Recycler", ability_name="Circular Supply Chain", ability_text="Robot-Slayer Recycler knows that when the elegant solution fails, you strip it back to physics and rebuild from first principles. Whenever a round's ARR exceeds the blind target by 2× or more (overkill), 30% of the excess converts directly to Cash. Additionally, each time this triggers, Margin increases by 1 percentage point (max +5%). This rewards building far past the minimum — waste from one cycle becomes feedstock for the next.", rarity="Common", salary=5, groups={"tesla-cofounders"}, hint="Overkill ARR → Cash + scaling Margin", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}, ops={{k="grant", what="cash", per="overkill", coef=0.3}, {k="grant", what="margin", amount=0.01, max=0.05}}}},
  {key="f_jeff-bezos", effect_brief="+0.2×Rev per Ship, stacks all run", set="Founder", name="Cowboy of Day One", short="One", ability_name="Get Big Fast Flywheel", ability_text="The Cowboy of Day One never stops reinvesting. Each time you Ship an app, this joker's Xmult rises by +0.2 permanently — no resets between rounds or antes. It starts at X1 and snowballs across the run: the bigger the empire you're building, the harder each unit of revenue compounds. Reward for staying in the game and Shipping over and over rather than banking safe profit.", rarity="Legendary", salary=40, groups={"J Team", "s-team"}, hint="Every Ship permanently turns the flywheel…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.2*ships_this_run", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.2, per="ships_this_run"}}}},
  {key="f_jeff-dean", effect_brief="+2% Margin permanently per blind cleared", set="Founder", name="Compiler's Dread", short="Dread", ability_name="Rebuild the Floor", ability_text="The Compiler's Dread hits a hard limit and redesigns the floor beneath it — every time. The first time each blind is cleared, Margin rises by +2% permanently (no cap). Because Cash income = Margin × ARR, every infrastructure upgrade pays dividends for the rest of the run: the deeper you go, the richer the floor.", rarity="Rare", salary=20, groups={"google-brain-founders", "google-deepmind-leadership"}, hint="permanently increases Margin each time yo…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="Margin += 2% per blind cleared (cumulative)", ke_complement=false}, dsl={hook="blind_won", once=true, once_scope="blind", ops={{k="grant", what="margin", amount=0.02}}}},
  {key="f_jeffrey-katzenberg", effect_brief="+50 Users once/blind if behind target", set="Founder", name="Grudge Greenlighter", short="Greenlighter", ability_name="Six Weeks Ahead", ability_text="The Grudge Greenlighter only moves when cornered. When you play a hand and your current Users score is still below the Blind's target, this hand gains +50 Users — flood the market before the incumbent lands. The burst fires once per Blind. If any other Founder joker is also in play, the bonus doubles to +100 Users. It never fires if you are already ahead.", rarity="Common", salary=5, hint="plus_chips burst when current Users trail…", effect={type="plus_chips", scaling="conditional_burst", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="50 (100 if any other Founder joker in play), fires once per…", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op="<", val=1}, ops={{k="scale", field="chips", base=50, coef=0}}, once=true, once_scope="blind"}},
  {key="f_jensen-huang", effect_brief="+0.25 xRev permanently each Ship, ratchets all run", set="Founder", name="Shovel Saint", short="Saint", ability_name="CUDA Lock-In", ability_text="The Shovel Saint never bets on which AI startup wins — he sells the shovels to all of them. Every Ship, this founder's lock-in deepens: its xRev grows by +0.25 permanently for the rest of the run, then applies the whole accumulated multiplier when scoring. The longer the platform compounds, the more indispensable it becomes — a ratchet that only ever climbs, rewarding patience.", rarity="Legendary", salary=40, hint="Permanent xMult that ratchets up every ti…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.25*founders_hired_this_run", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.0, coef=0.25, step="ship", when="post", state="shovel", max=16}}}},
  {key="f_jerry-liu", effect_brief="+8 Users/round uncapped; +12 Users/Data card (2+ Data)", set="Founder", name="Llama Whisperer", short="Whisperer", ability_name="Data Pipeline Moat", ability_text="The Llama Whisperer knows that when models commoditize, the data orchestration layer becomes the unassailable advantage. While this Founder is hired your Users value grows by +8 each round, and the moat deepens uncapped the longer you hold him. On every Ship, if your played hand has at least 2 Data-layer cards, gain an extra +12 Users for each Data card in the hand.", rarity="Common", salary=5, groups={"ai-engineer-wave", "ex-robust-intelligence"}, hint="scaling-over-time (grows each round held)…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0.0, coef=8, state="plus_chips", when="post", step="round"}, {k="scale", field="chips", per="cards_of_layer", layer="Data", coef=12, gate={g="count", per="cards_of_layer", layer="Data", op=">=", val=2}}}}},
  {key="f_jerry-yang", effect_brief="+1 Rev/user per card held back each round (compounds)", set="Founder", name="Sake Whisperer", short="Whisperer", ability_name="First Mover Relationship", ability_text="The Sake Whisperer bets early and waits. Each round, his Patience grows by every card you held back unplayed — and pays it all out as Rev/user. The fewer cards you ship now, the harder patience compounds later. All bold strategies carry risk: the longer you wait, the more you stake on one big pour.", rarity="Uncommon", salary=10, groups={"early-yahoo-team"}, hint="scaling-over-time + ARR multiplier on ear…", effect={type="retrigger", scaling="scaling_persistent", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="", ke_complement=false}, dsl={ hook="joker_main", ops={ { k="acc", field="mult", coef=1, state="patience", step="round", inc_per="unplayed_cards", when="post" } } }},
  {key="f_jim-clark", effect_brief="×1.5 ARR on new App Type; +Margin grows", set="Founder", name="Cap-Table Pirate", short="Pirate", ability_name="Land-Grab IPO", ability_text="The Cap-Table Pirate arrives first, owns the round, and goes public before rivals realize there is a market. When you Ship a hand that scores a new App Type you have never scored this run, immediately multiply that round's ARR by ×1.5. If you spent Cash from your own balance rather than a voucher this round, gain +1 permanent Margin point on that App Type for the rest of the run. Once per Ante, poach one Talent card from the shop without paying its Salary cost — permanently raising that card's contribution by +20 Users but costing 5% of current run ARR as a dilution fee. Each distinct new-market first-score increases the ARR multiplier by +0.25.", rarity="Uncommon", salary=10, groups={"University of Utah"}, hint="ARR (valuation spike) + Cash (self-fundin…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="new_app_types", op=">", val=0}, ops={{k="acc", field="x_mult", base=1.5, coef=0.25, state="newmkt", when="pre", step="ship", max=14}}}},
  {key="f_jimmy-ba", effect_brief="+80 Users once if full-layer Coverage shipped", set="Founder", name="ArXiv Anyway", short="Anyway", ability_name="ArXiv Anyway", ability_text="The ArXiv Anyway posted the paper the gatekeepers called worthless — and it became foundational to every model trained since. The first time in a run you Ship an App Type whose Coverage spans every distinct Layer you have in your current deck, +80 Users fires once. The burst fires exactly once per run: the moment of vindication, when full-stack coverage finally lands.", rarity="Uncommon", salary=10, groups={"xai-founding-team", "toronto-ai-group"}, hint="one-time conditional +Users burst when yo…", effect={type="plus_chips", scaling="conditional_burst", hook="after", primitive_hint="chips", engine_status="executable", magnitude="80 (once per run, triggers when played hand Coverage == dis…", ke_complement=false}, dsl={hook="after", gate={g="count", per="distinct_layers", op=">=", val=5}, ops={{k="scale", field="chips", base=80.0, coef=0}}, once=true, once_scope="run"}},
  {key="f_jimmy-wales", effect_brief="Dissolves 1 clash per distinct Layer seen this run", set="Founder", name="Wiki Wildfire", short="Wildfire", ability_name="Constitutional Monarch", ability_text="The Wiki Wildfire never scored a thing himself — he just tore down the walls that kept tech stacks from working together. The more of the stack your run has explored, the more barriers fall: each scoring hand, dissolves 1 compatibility clash for every distinct Layer your run has ever played. Open up the whole stack (all 5 Layers) and almost any combination plays clean.", rarity="Uncommon", salary=10, hint="utility (scaling_persistent): each first-…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 compatibility-edge-group unlocked per new Layer seen (max…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", per="distinct_layers_seen_run", base=0, coef=1}}}},
  {key="f_joe-tsai", effect_brief="Salary waived while held; +1 Rev per round held (compounds)", set="Founder", name="Six-Hundred-Dollar Bet", short="Bet", ability_name="Equity Over Salary", ability_text="The Six-Hundred-Dollar Bet took equity over a paycheck and never looked back. While he is on your team his Salary is waived (his founder pay is relieved each round). And the longer you hold the position, the more that equity vests: he gains a permanent +1 Rev for every round you have held him, compounding every Blind.", rarity="Common", salary=5, hint="Salary reduction → scaling ARR bonus", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={passive={what="salary", amount=2}, hook="joker_main", ops={{k="acc", field="mult", state="vest", step="round", base=0, coef=1, reset_on={"selling_self"}}}}},
  {key="f_joel-spolsky", effect_brief="+8 Rev if 2+ Layers shipped", set="Founder", name="Hundred-Percent Prophet", short="Prophet", ability_name="Hundred Percent of the Surv…", ability_text="The Hundred-Percent Prophet built his entire company on one distribution channel — and it worked so cleanly that when he checked, every single customer had found him the same way. When you Ship a round that includes tech cards from at least 2 distinct Layers, gain +8 Rev for that scoring pass (once per round). No VC, no ads, no sales team — just full-stack credibility converting readers into buyers the instant the product is real.", rarity="Common", salary=5, hint="+8 Rev once per round when you Ship with…", effect={type="plus_mult", scaling="conditional_burst", hook="before", primitive_hint="mult", engine_status="executable", magnitude="8 (once per round, triggers when distinct_layers_in_hand >=…", ke_complement=false}, dsl={hook="before", gate={g="count", per="distinct_layers", op=">=", val=2}, ops={{k="scale", field="mult", base=8.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_john-doerr", effect_brief="+0.16 xRev permanently each Ship clearing 2x target", set="Founder", name="OKR Evangelist", short="Evangelist", ability_name="Measure What Matters", ability_text="Set an audacious OKR: don't just beat the blind, double it. Each Ship whose ARR clears 2x the funding stage's target hits your Objective and grows Measure What Matters permanently — +0.16 to xRev, banked for the rest of the run. Ships that merely scrape past the bar earn nothing. Think 10x, not 10%: only the outrageous wins compound.", rarity="Uncommon", salary=10, hint="Revenue-per-user (×Rev), gated on a self…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=2.0}, ops={{k="acc", field="x_mult", base=1.0, coef=0.16, state="okr", when="post", step="ship", max=25}}}},
  {key="f_john-lasseter", effect_brief="x3 Rev, 1st clean (all-distinct-Layer) Ship each round", set="Founder", name="Re-Board Oracle", short="Oracle", ability_name="Oscar Moment", ability_text="The Re-Board Oracle never ships a reel until it's genuinely great. The first time each round you Ship a clean build — every played card a distinct Layer, no redundancy — that polished Ship triggers a one-time x3.0 Rev burst. A sloppy Ship (any repeated Layer) earns nothing; the masterpiece does.", rarity="Common", salary=5, hint="xmult burst when a Ship follows 2+ Pivots…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="x3.0 once per round, gated on pivot_count >= 2 this round", ke_complement=false}, dsl={hook="joker_main", gate={g="all_distinct_layers"}, ops={{k="scale", field="x_mult", base=3.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_john-mauchly", effect_brief="×(1+0.15 per Layer) each Ship", set="Founder", name="Idea Magpie", short="Magpie", ability_name="Idea Bee", ability_text="The Idea Magpie's edge was synthesis — pulling from weather data, vacuum-tube physics, rival prototypes, and architecture papers, fusing them into something no single source contained. Each round, ARR is multiplied by 1 + 0.15× (distinct Layers played this round). A full 5-Layer hand yields a ×1.75 ARR bonus. The more sources in the hand, the bigger the synthesis payoff.", rarity="Rare", salary=20, groups={"mauchly-eckert-team"}, hint="scaling-over-time: each distinct source y…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.15, per="distinct_layers"}}}},
  {key="f_john-mccarthy", effect_brief="+×0.15 Rev per AI card, forever", set="Founder", name="Namer of Things", short="Things", ability_name="Named the Category", ability_text="The Namer of Things coined the term that attracted decades of funding and talent — the name itself was the killer product. Every AI-layer card that contributes to a Ship permanently increments this joker's xMult by x0.15 (compounding across the run). Starts at x1.0 so the first AI card played feels like naming the field: suddenly there is a field.", rarity="Rare", salary=20, groups={"MIT Artificial Intelligence Lab", "Stanford"}, hint="xmult grows permanently each time an AI-l…", effect={type="xmult", scaling="scaling_persistent", hook="individual", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.15 * ai_layer_cards_scored_this_run", ke_complement=false}, dsl={hook="individual", gate={g="card_layer", layer="AI"}, ops={{k="acc", field="x_mult", base=1.0, coef=0.15, state="mccarthy_ai", when="post", max=26}}}},
  {key="f_john-schulman", effect_brief="+$20 once on 3rd App Type played", set="Founder", name="Thirty-Card Monk", short="Monk", ability_name="Minimal Feedback Dividend", ability_text="The Thirty-Card Monk finds the smallest possible intervention whose feedback signal generalizes everywhere. The moment you play your 3rd distinct App Type hand this run — proof that your product feedback loop is generalizing across Layers — the engine pays out a one-time cash injection of $20. One careful experiment, everywhere at once.", rarity="Uncommon", salary=10, groups={"ex-openai-diaspora", "openai-founders"}, hint="one-time cash injection when the 3rd dist…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="$20 (fires once when distinct_app_types_played >= 3)", ke_complement=false}, dsl={hook="after", gate={g="count", per="distinct_app_types_shipped", op=">=", val=3}, ops={{k="grant", what="cash", amount=20}}, once=true, once_scope="run"}},
  {key="f_john-sowa", effect_brief="Cancels clashes; each→+Rev (3+L)", set="Founder", name="Babel Bridger", short="Bridger", ability_name="Conceptual Bridge", ability_text="The Babel Bridger knows that incompatibility between systems is not a fundamental obstacle — it is a translation problem, and the right structure always serves as the bridge. When you Ship a hand whose built-stack spans cards from 3 or more distinct Layers, any Compatibility-graph penalties from mismatched tech pairs are cancelled, and each cancelled penalty contributes +1×Rev instead. At 5 Layers covered, the bonus upgrades to ×1.5 applied after all other Rev. Inert on mono-layer or two-layer hands: there is nothing to bridge.", rarity="Uncommon", salary=10, groups={"aaai-fellows", "ibm-research-alumni"}, hint="×Rev scaling with stack heterogeneity (i…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="before", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="clash_tax", field="mult", per=-1}, {k="clear_clash", amount="all"}, {k="scale", field="x_mult", base=1.0, coef=0.1, per="distinct_layers"}}}},
  {key="f_john-warnock", effect_brief="Clears 1 clash per distinct Layer ever scored this run", set="Founder", name="Mumbo-Jumbo Slayer", short="Slayer", ability_name="Lingua Franca", ability_text="The Mumbo-Jumbo Slayer wins not by locking things down but by making the open standard so technically perfect that friction vanishes as you adopt the stack. Each distinct Layer your startup has ever scored this run dissolves one compatibility clash on every hand. By mid-run, with most of your stack standardised, the mismatch penalty is all but erased while rivals still pay the friction tax.", rarity="Uncommon", salary=10, groups={"University of Utah"}, hint="permanently removes compatibility clashes…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 Layer standardised per first-score of that Layer; max 5 (…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", per="distinct_layers_seen_run", base=0, coef=1}}}},
  {key="f_johnny-ho", effect_brief="+$8 Cash when ARR≥2× blind", set="Founder", name="Perfect Pruner", short="Pruner", ability_name="Harvest the Edge", ability_text="The Perfect Pruner maps the problem space, crosses out every branch but one, and commits only when the solution is provably optimal. When a shipped hand produces ARR ≥ 2× the current blind target (overkill), immediately gain $8 Cash. Triggers at most once per round — the window closes the moment you've taken it. Rewards tight hand selection and reading the board, not brute-force spam.", rarity="Common", salary=5, hint="one-time cash burst when shipped hand cle…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="8 if ARR >= 2 * blind_target else 0", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}, ops={{k="grant", what="cash", amount=8}}, once=true, once_scope="blind"}},
  {key="f_jonathan-ross", effect_brief="+3 Users/run per Infra+AI card", set="Founder", name="Twenty-Percent Wizard", short="Wizard", ability_name="On-Chip Pipeline", ability_text="The Twenty-Percent Wizard built the first prototype on stolen nights, then redesigned the architecture from first principles to eliminate every bottleneck. After each hand, gain +3 Users (Users) permanently for every Infra or AI layer card played in that hand. The bonus accumulates across the entire run — another lane added to the conveyor each time you field a deep AI/Infra stack.", rarity="Uncommon", salary=10, hint="Each hand played permanently adds Users e…", effect={type="plus_chips", scaling="scaling_persistent", hook="after", primitive_hint="chips", engine_status="executable", magnitude="3 * infra_ai_cards_played_this_hand (added permanently each…", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="chips", base=0.0, coef=3.0, inc_per="cards_of_layer", layer="Infra", state="opw_infra", when="post"}, {k="acc", field="chips", base=0.0, coef=3.0, inc_per="cards_of_layer", layer="AI", state="opw_ai", when="post"}}}},
  {key="f_josh-albrecht", effect_brief="+30 Users if 2+ Layers, hired first", set="Founder", name="Overnight Optimizer", short="Optimizer", ability_name="19-Parameter Sweep", ability_text="The Overnight Optimizer hits go, goes to sleep, and wakes up to having every parameter perfectly tuned — squeeze every unit of compute before you ever scale up. If Overnight Optimizer was on the table before the first card of the hand was played and the hand contains cards from 2 or more distinct Layers, score +30 Users. Interrupt the sweep — hire him mid-hand or play a mono-Layer hand — and it finds nothing.", rarity="Common", salary=5, hint="plus_chips burst — if held from before th…", effect={type="plus_chips", scaling="conditional_burst", hook="individual", primitive_hint="chips", engine_status="executable", magnitude="30 if held_before_hand_start and distinct_layers_played >=…", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="distinct_layers", op=">=", val=2}, ops={{k="scale", field="chips", base=30, coef=0}}}},
  {key="f_josh-kushner", effect_brief="Repeat App Types: +$, grows/play", set="Founder", name="Sole Term Sheet", short="Sheet", ability_name="Follow-On Conviction", ability_text="Sole Term Sheet quietly builds conviction while everyone else equivocates. The first time you play any App Type this run, nothing happens — he's watching. Each subsequent play of that same App Type earns $2 immediately, and the per-type bonus grows by $1 with every additional replay (2nd play gives $2, 3rd gives $3, 4th gives $4…). Cash accumulates across the whole run and stacks independently per App Type. A concentrated single-archetype run snowballs hardest; spread across many App Types it trickles.", rarity="Common", salary=5, hint="each time you replay an App Type you have…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="2 + (plays_on_this_type - 2) dollars per replay (first play…", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="dollars", key="scoring_name", base=0, coef=1, when="post", state="jk"}}}},
  {key="f_julien-chaumond", effect_brief="After each round, add 1 random tech card to deck", set="Founder", name="Cold-Email Magnet", short="Magnet", ability_name="Cold Email Acquisition", ability_text="Cold-Email Magnet spots a missing piece in the ecosystem, reaches out with zero intro, and the platform grows by absorbing it. After each round won, add one random tech card to your deck. Round by round the deck quietly fills with tools pulled in from across the stack.", rarity="Common", salary=5, groups={"french-ai-founders", "ecole-polytechnique-alumni"}, hint="generation: permanently absorbs adjacent…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 tech card per distinct Layer absorbed so far (max 5 over…", ke_complement=false}, dsl={hook="blind_won", ops={{k="gen", kind="tech_card"}}}},
  {key="f_kanjun-qiu", effect_brief="+8 Rev if prev hand missed target", set="Founder", name="Dead-End Sage", short="Sage", ability_name="Avalon Dead-End", ability_text="Dead-End Sage doesn't iterate blindly into failure — she names the dead-end and changes course. If your previous hand in this blind scored below the target ARR, this hand gains +8 Rev. The correction pays off, not the failure. Triggers at most once per blind — you only get one pivot.", rarity="Common", salary=5, hint="+8 Rev on the hand immediately after a h…", effect={type="plus_mult", scaling="conditional_burst", hook="before", primitive_hint="mult", engine_status="executable", magnitude="+8 if prev_hand_score < blind_target else 0", ke_complement=false}, dsl={hook="before", gate={g="previous_arr_ratio", op="<", val=1}, ops={{k="scale", field="mult", base=8.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_karen-simonyan", effect_brief="+40 Users if 3+ Layers played", set="Founder", name="Deeper Stacker", short="Stacker", ability_name="Goes to Nineteen", ability_text="Deeper Stacker bets everything on the simplest possible answer: just go deeper. When a played hand spans 3 or more distinct tech Layers, gain +40 Users immediately. Below the threshold nothing triggers — the advantage is invisible at shallow depth and only reveals itself once you commit to full coverage.", rarity="Common", salary=5, groups={"deepmind-diaspora", "oxford-ai-diaspora", "inflection-ai-founders", "oxford-ai-cluster"}, hint="plus_chips conditional burst — if the pla…", effect={type="plus_chips", scaling="conditional_burst", hook="after", primitive_hint="chips", engine_status="executable", magnitude="+40 chips if distinct_layers_played >= 3, else 0", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="scale", field="chips", base=40, coef=0}}}},
  {key="f_keith-rabois", effect_brief="+$1/hand per active App-Type barrel", set="Founder", name="Barrel Diviner", short="Diviner", ability_name="Barrel Budget", ability_text="Barrel Diviner knows that a startup can do exactly as many things simultaneously as it has people who can drive an idea end-to-end — no more. After each hand scores, count the number of distinct App Types that contributed at least one card. Permanently increase this founder's cash-per-hand payout by +$1 for each active barrel. Every barrel you identify is a permanent capability you can spend against.", rarity="Common", salary=5, groups={"paypal-mafia", "PayPal Mafia"}, mafia=true, hint="permanently earn +$1 per scoring App Type…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="floor(1 * active_barrel_count_cumulative)", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="dollars", base=0, coef=1, per="distinct_app_types_shipped"}}}},
  {key="f_ken-howery", effect_brief="-15% Salary/ante; +20% of surplus Rev as Cash", set="Founder", name="Quiet Closer", short="Closer", ability_name="Runway Extension", ability_text="Quiet Closer keeps the machine funded longer than anyone else — not through splashy moves but relentless capital management. At the end of each Ante, cut this round's Salary by 15% (banked, not spent). Then bank 20% of any surplus Rev above the Blind target as Cash. Cost containment plus overkill harvest: a war chest that grows even as you scale.", rarity="Common", salary=5, groups={"paypal-mafia", "founders-fund-leadership"}, mafia=true, hint="Cash generation / survival economy (cuts…", effect={type="economy", scaling="flat", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="salary", pct=0.15}, {k="grant", what="cash", per="overkill", coef=0.2}}}},
  {key="f_kevin-systrom", effect_brief="+20 Users if you Ship 2 cards or fewer this round", set="Founder", name="One-Filter Wonder", short="Wonder", ability_name="One Filter, Thirty Million", ability_text="One-Filter Wonder knows one afternoon of focused subtraction can unlock everything. Strip the build down: if you Ship a lean hand of 2 cards or fewer, it gains +20 Users. Fires once per round — restraint meets execution and the viral unlock follows. Bloat, no burst.", rarity="Uncommon", salary=10, hint="plus_chips burst — if you discarded at le…", effect={type="plus_chips", scaling="conditional_burst", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="20 if discards_this_round >= 1 else 0", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="hand_size", op="<=", val=2}, ops={{k="scale", field="chips", base=20.0, coef=0}}, once=true, once_scope="blind"}},
  {key="f_kimbal-musk", effect_brief="+30 Users once on hand 7 of run", set="Founder", name="141st Caller", short="Caller", ability_name="The 141st Call", ability_text="141st Caller keeps dialing after every rejection until the door swings open — not because he out-argues anyone, but because he genuinely won't let go. The first time you have played 7 or more hands total in the current run, gain +30 Users for this scoring hand, once per run. It cannot trigger early; it cannot trigger twice. The moment is fixed, inevitable, earned.", rarity="Common", salary=5, groups={"musk-family"}, hint="One-time +Users burst once cumulative han…", effect={type="plus_chips", scaling="conditional_burst", hook="individual", primitive_hint="chips", engine_status="executable", magnitude="30 (once, when hands_played_this_run >= 7)", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="ships_this_run", op=">=", val=6}, ops={{k="scale", field="chips", base=30.0, coef=0}}, once=true, once_scope="run"}},
  {key="f_larry-ellison", effect_brief="+×0.2 Rev per Ship, never resets", set="Founder", name="Vigorish Shogun", short="Shogun", ability_name="Vigorish Clause", ability_text="Vigorish Shogun's real genius was switching costs: once a customer ran his database, leaving cost more than staying — so they paid the vigorish forever. Each time you successfully Ship (score above the Blind target), this card gains +0.2×Rev permanently. The multiplier never resets between antes. The longer you stay locked in, the more it extracts.", rarity="Rare", salary=20, hint="xMult grows permanently each round you sc…", effect={type="xmult", scaling="scaling_persistent", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.2 * ships_above_blind_this_run", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="x_mult", base=1.0, coef=0.2, state="xmult", when="post", max=20}}}},
  {key="f_larry-page", effect_brief="+x0.2 Rev each newly-adopted Layer (permanent)", set="Founder", name="Ten-Billion Mumble", short="Mumble", ability_name="Inbound Authority", ability_text="Ten-Billion Mumble thinks in graphs, not ceilings. At the end of each Ship, for every Layer you adopt for the first time this run, permanently gain +0.2x Rev for the rest of the run. The authority graph you build only ever grows -- value is never in the node but in everything pointing at it.", rarity="Legendary", salary=40, groups={"googlers"}, hint="Each new Synergy link to your graph perma…", effect={type="xmult", scaling="scaling_persistent", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="x_mult += 0.2 per newly-activated Synergy edge", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="x_mult", base=1.0, coef=0.2, state="authority", inc_per="new_layers", when="post", max=20}}}},
  {key="f_leonard-bosack", effect_brief="Ship: ignore 1 clash per distinct Layer beyond the first", set="Founder", name="Manhole Whisperer", short="Whisperer", ability_name="Through the Manhole", ability_text="Manhole Whisperer rewired incompatible networks without permission — the rules were for other people. When you Ship, for each distinct Layer in your played hand beyond the first, one compatibility clash among those cards is routed away and ignored for this score. The more heterogeneous the stack you ship, the more clashes he quietly resolves.", rarity="Uncommon", salary=10, hint="permanently widens compatibility: each di…", effect={type="utility", scaling="scaling_persistent", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="clash_suppressions = max(0, distinct_layers - 1)", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", base=-1, coef=1, per="distinct_layers"}}}},
  {key="f_linus-torvalds", effect_brief="Infra/Backend retrigger; +2 Users/founder/Ship", set="Founder", name="Kernel Panic Dad", short="Dad", ability_name="Given Enough Eyeballs", ability_text="Kernel Panic Dad gives it away freely and lets the contributors make it strong. Each round you hold this founder, your played Infra and Backend cards each score +1 retrigger (one extra scoring pass). Additionally, every other founder card in your hire slots contributes +2 Users to each Ship. The effect grows with team size, not market spend.", rarity="Rare", salary=20, hint="scaling-over-time (Users / Users compound…", effect={type="retrigger", scaling="scaling_per_round", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="", ke_complement=false}, dsl={retrigger=1, gate={g="or", gs={{g="card_layer", layer="Infra"}, {g="card_layer", layer="Backend"}}}}},
  {key="f_llion-jones", effect_brief="×1.5 ×Rev, +×0.25 per Founder hired this run", set="Founder", name="Transformer's Ex", short="Ex", ability_name="Sick of Transformers", ability_text="Transformer's Ex is done milking an eight-year-old architecture: a deep bench beats a sacred paradigm. She enters at ×1.5 ×Rev and gains +×0.25 ×Rev for every Founder you've brought aboard this run — the more legends on your cap table, the more her conviction compounds. You should only do work that would not happen if you weren't the one doing it.", rarity="Rare", salary=20, groups={"transformer-eight", "ex-google-ai-diaspora"}, hint="permanent xmult that grows each time you…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.5 + 0.25 * founders_sold", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.5, coef=0.25, per="founders_hired_this_run"}}}},
  {key="f_lucy-guo", effect_brief="Each Ship: +5% of ARR Cash, +$1/round held (max $8)", set="Founder", name="Patient Billionaire", short="Billionaire", ability_name="Retained Stake", ability_text="Patient Billionaire was cut from her own company but kept her equity, and the fortune was earned entirely by not selling. While she is hired, every Ship pays you a retained-equity dividend: 5% of that hand's ARR in Cash, plus a Stake bonus of +$1 for every round she has been on your cap table (up to +$8). The longer she sits, the larger the dividend — patience pays.", rarity="Common", salary=5, groups={"thiel-fellowship", "y-combinator-alumni"}, yc=true, hint="scaling-over-time / Cash generation from…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="dollars", per="running_arr", stage="pre_after", coef=0.05}, {k="acc", field="dollars", base=0, coef=1, step="round", max=8, state="stake", reset_on={"selling_self"}}}}},
  {key="f_luke-nosek", effect_brief="+20 Users + 5/Layer if 2+ Layers played (once)", set="Founder", name="Napkin Prophet", short="Prophet", ability_name="Double-Sided Referral Loop", ability_text="Napkin Prophet discovered that rewarding both sides of a network at once is what bends a growth curve exponential. The first time you play a hand containing cards from at least 2 distinct Layers, the referral loop completes both sides at once: gain +20 Users immediately, plus +5 Users for each distinct Layer beyond the first. Like the incentive program itself, this fires once and exactly once — ending it early was a mistake, so the burst is your only shot to bank it.", rarity="Common", salary=5, groups={"paypal-mafia", "founders-fund-leadership"}, mafia=true, hint="plus_chips: one-time Users burst when a t…", effect={type="plus_chips", scaling="conditional_burst", hook="after", primitive_hint="chips", engine_status="executable", magnitude="20 + 5*(distinct_layers_in_hand - 1)", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="chips", base=15, coef=5, per="distinct_layers"}}, gate={g="count", per="distinct_layers", op=">=", val=2}, once=true, once_scope="run"}},
  {key="f_marc-andreessen", effect_brief="+1.5 Rev/Ship while focused; ×2 Rev on full-stack Ship", set="Founder", name="Barefoot King", short="King", ability_name="Software Eats The World", ability_text="Barefoot King backs the contrarian bet before the market agrees. Every time you Ship a focused hand (NOT yet covering all five Layers), conviction builds: permanently gain +1.5 Rev. The moment you Ship a full-stack hand that finally covers all five Layers, the market catches up and your accumulated conviction pays out at ×2 Rev. Software eats the world.", rarity="Rare", salary=20, groups={"uiuc-mosaic-developers", "a16z-leadership"}, hint="Revenue-per-user (Rev) — thesis-convicti…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={ {k="acc", field="mult", base=1.5, coef=1.5, state="conviction", step="ship", when="post", gate={g="not", g1={g="all_distinct_layers"}}}, {k="scale", field="x_mult", base=2.0, coef=0.0, gate={g="all_distinct_layers"}} }}},
  {key="f_marc-benioff", effect_brief="+4 Rev on lean hand; +x0.1 Rev/round held (cap x2)", set="Founder", name="No-Software Prophet", short="Prophet", ability_name="End of Software", ability_text="No-Software Prophet named the enemy and made buying less software feel like a moral stance. When you Ship a lean hand with no redundant Layers (every card a distinct Layer), gain +4 Rev this round. And each consecutive round he stays hired, your ×Rev grows by +x0.1 (x1.1 after one round, x1.2 after two...), the subscription compounding up to a cap of x2.0. Build lean against the incumbent; let the subscription compound.", rarity="Uncommon", salary=10, hint="conditional +Rev (anti-incumbent) + scal…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=4.0, gate={g="all_distinct_layers"}}, {k="acc", field="x_mult", base=1.0, coef=0.1, step="round", max=10, when="post", state="sub", reset_on={"selling_self"}}}}},
  {key="f_mark-pincus", effect_brief="ARR 2x target -> excess to Cash 1:3; +$1/App Type shipped", set="Founder", name="Click Shepherd", short="Shepherd", ability_name="Click Omniscience", ability_text="Click Shepherd runs the virtual-goods engine on top of free-to-play, monetizing every signal rivals waste. At the end of each round, if your ARR is 2x the funding target or more, the excess ARR is cashed out at a 1:3 ratio. Plus a steady data dividend: +$1 Cash for each distinct App Type you have shipped this run.", rarity="Common", salary=5, groups={"sf-social-networking-mafia"}, mafia=true, hint="+Users (Users) scaling via data-driven re…", effect={type="plus_chips", scaling="conditional_burst", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="cash", per="overkill", coef=0.3333, gate={g="arr_ratio", stage="pre_after", op=">=", val=2}}, {k="grant", what="cash", per="distinct_app_types_shipped", coef=1}}}},
  {key="f_mark-zuckerberg", effect_brief="xRev +0.10/round held, +0.10 per other Founder", set="Founder", name="Cross-Legged Throne", short="Throne", ability_name="I'm CEO, Bitch", ability_text="Cross-Legged Throne refuses every acquisition — control is the only thing that matters. Starts at x1.0 Rev. His Voting-Control counter climbs each round he is NOT sold, gaining +0.10 xRev permanently per round held; selling him resets the throne to zero. And the whole table answers to him: while hired, he gains an additional +0.10 xRev for every OTHER Founder you own. The longer you refuse to exit and the deeper your bench, the more Revenue flows through the throne.", rarity="Legendary", salary=40, groups={"facebook-founding-quartet", "kirkland-house-suite-h33"}, hint="Synergy / founder-control voting (10x sup…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.0, coef=0.10, state="vote", when="post", step="round", reset_on={"selling_self"}, max=40}, {k="scale", field="x_mult", base=1.0, coef=0.10, per="others"}}}},
  {key="f_martin-eberhard", effect_brief="+0.4x Rev per Ship, up to x3; resets on lost blind", set="Founder", name="Spreadsheet Prophet", short="Prophet", ability_name="Well-to-Wheels", ability_text="Spreadsheet Prophet runs the numbers until the answer is undeniable. Each App Type you Ship adds a permanent +0.4x to his conviction (the math compounds). On every Ship his accumulated conviction fires as a x Rev burst, growing from x1 toward a x3 cap (5 ships) as the spreadsheet keeps proving him right. A failed blind resets his conviction to zero.", rarity="Common", salary=5, groups={"tesla-cofounders"}, hint="scaling-over-time (×Rev grows each round…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", state="conviction", step="ship", when="post", base=1, coef=0.4, max=5, reset_on={"blind_lost"}}}}},
  {key="f_marvin-minsky", effect_brief="×Rev scales ×1.5→×5 with distinct Layers played", set="Founder", name="Swarm Whisperer", short="Whisperer", ability_name="Society of Mind", ability_text="Swarm Whisperer proved that no single agent is intelligent — but joined in societies in the right way, they produce true intelligence. Each scored Layer card adds a thin universal +Users bump to ALL Layers in the build. The joker's ×Rev is the emergent society bonus: it grows with the number of DISTINCT Layers joined together in your hand (×1.5 / ×2 / ×3 / ×4 / ×5 as you reach 1→5 distinct Layers). A single isolated card barely scores; a diverse society of agents scores hugely. Only the full hand has any value at all.", rarity="Legendary", salary=40, groups={"mit-ai-lab-founders", "ai-founding-fathers"}, hint="×Rev that scales with stack diversity (s…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="scale", field="chips", base=0, coef=4, per="hand_size"}, {k="scale", field="x_mult", base=0.625, coef=0.875, per="distinct_layers"}}}},
  {key="f_mary-meeker", effect_brief="×2.5 Rev if 3+ distinct Layers in hand", set="Founder", name="Wave Caller", short="Caller", ability_name="Trends Report Drop", ability_text="Wave Caller drops a trends report and the whole market reprices overnight. When the scored hand covers 3 or more distinct Layers, Rev is multiplied by ×2.5 for that hand. Below the threshold nothing triggers — she doesn't publish half a thesis.", rarity="Uncommon", salary=10, hint="xmult spike when your hand spans 3+ disti…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="x2.5 if distinct_layers >= 3, else x1", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=2.5, coef=0}}, gate={g="count", per="distinct_layers", op=">=", val=3}}},
  {key="f_masayoshi-son", effect_brief="ARR >=2x target: +20% of ARR as Cash", set="Founder", name="96% Gambler", short="Gambler", ability_name="Animal Smell", ability_text="The 96% Gambler reads the room in six minutes and bets civilizational-scale capital on pure instinct. When this round's ARR lands at twice the funding target or better, he cashes the bet: 20% of your ARR is paid straight out as Cash. He only collects when the room is winning big.", rarity="Legendary", salary=40, hint="scaling-over-time + conditional overkill-…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}, ops={{k="scale", field="dollars", per="running_arr", stage="pre_after", coef=0.2}}}},
  {key="f_matei-zaharia", effect_brief="+2 Users/round held (permanent); 3+ Layers: retrigger top card", set="Founder", name="Memory Whisperer", short="Whisperer", ability_name="Open-Source Standard", ability_text="Memory Whisperer spots the one flaw no one else named and fixes it cleanly — then does it again, and again. Each round this founder is held he gains a permanent +2 Users, compounding for the rest of the run. And when you Ship a hand touching 3 or more distinct Layers, he retriggers the highest-Users card played — the compound system fires twice.", rarity="Uncommon", salary=10, groups={"uc-berkeley-amplab", "apache-spark-seven"}, hint="scaling-over-time + Synergy (infrastructu…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0, coef=2, state="whisper", step="round", when="post"}}, retrigger=1, retrigger_target="highest", gate={g="count", per="distinct_layers", op=">=", val=3}}},
  {key="f_max-levchin", effect_brief="No Salary; clean blind clear: +1 perm x-Rev & $3 Cash", set="Founder", name="Impenetrable Russian", short="Russian", ability_name="Underwrite or Lose", ability_text="Impenetrable Russian charges no Salary — total alignment with your users. Each round you clear the blind cleanly — comfortably above target (1.25x) on a hand of all-distinct Layers, no redundancy — gain +1 permanent x-Rev and bank $3 Cash. A squeaker or a sloppy, padded stack earns him nothing: he only profits when your product genuinely pays.", rarity="Uncommon", salary=10, groups={"paypal-mafia", "uiuc-acm"}, mafia=true, hint="Margin (and risk discipline)", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="and", gs={{g="arr_ratio", stage="pre_after", op=">=", val=1.25}, {g="all_distinct_layers"}}}, ops={{k="acc", field="x_mult", base=1.0, coef=1.0, state="lev", step="round", when="post", max=4}, {k="grant", what="cash", amount=3}}, passive={what="salary", amount=3}}},
  {key="f_michael-moritz", effect_brief="×Rev grows +0.2 each round held", set="Founder", name="Never-Sell Oracle", short="Oracle", ability_name="Grand-Slam Compounding", ability_text="Never-Sell Oracle refuses the premature exit and waits for the grand slam. Starts at ×1 Rev and gains +0.2 ×Rev every round held, compounding for the whole run. The longer you hold without cashing out, the bigger the eventual return — exactly the patience the doctrine demands.", rarity="Uncommon", salary=10, hint="xMult that grows every round it is held —…", effect={type="xmult", scaling="scaling_per_round", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.2*rounds_held", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.2, per="rounds_held"}}}},
  {key="f_michael-ovitz", effect_brief="Ship 3+ Layers: add a free tech card to deck (1/blind)", set="Founder", name="Rabbit Wrangler", short="Wrangler", ability_name="Build the Franchise", ability_text="Rabbit Wrangler walks in with the whole package already assembled — script, director, star, bundled into one deal. The first time each blind you Ship a hand covering 3 or more distinct Layers, he packages an extra into your stack: a free tech card is generated and added to your deck on the spot. Fires once per blind — you can't run the same dog race twice.", rarity="Common", salary=5, hint="generation — when a played hand spans 3+…", effect={type="generation", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 Founder card added to shop when distinct_layers_played >=…", ke_complement=false}, dsl={hook="after", once=true, once_scope="blind", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="gen", kind="tech_card", amount=1}}}},
  {key="f_michael-truell", effect_brief="+1 Rev/round; +20 Users per newly-shipped App Type", set="Founder", name="Blinking Cursor", short="Cursor", ability_name="Obsolescence Engine", ability_text="Blinking Cursor treats today's lineup as already obsolete and keeps iterating before anyone notices decay. This card permanently gains +1 Rev each round. Additionally, each App Type you Ship for the first time this run gives +20 Users that hand. Builders who keep rotating into fresh products harvest both bonuses; anyone shipping the same old thing all ante gets only the slow drip.", rarity="Uncommon", salary=10, groups={"ai-engineer-wave", "neo-scholars", "mit-class-of-2022"}, hint="scaling-over-time + conditional bonus on…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="obsolescence", when="post", step="round"}, {k="scale", field="chips", base=0.0, coef=20.0, per="new_app_types"}}}},
  {key="f_mike-krieger", effect_brief="≤4 founders: −30% Salary, +1 Rev/founder/Ship", set="Founder", name="Thirteen-Person Unicorn", short="Unicorn", ability_name="Lean Stack", ability_text="Thirteen-Person Unicorn reaches a billion users with a team small enough to fit in a van — every hire a deliberate trade-off against focus, not a free addition. While you have 4 or fewer Founders hired, all Founder Salaries are reduced by 30% and each Ship scores +1 Rev per Founder hired. The smaller the team, the tighter the bonus stack.", rarity="Uncommon", salary=10, hint="Salary reduction + ARR scaling bonus for…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="count", per="others", op="<=", val=3}, ops={{k="grant", what="salary", pct=0.30}, {k="scale", field="mult", base=1, coef=1, per="others"}}}},
  {key="f_mike-markkula", effect_brief="+$8 Cash each ante, unconditional", set="Founder", name="Garage Angel", short="Angel", ability_name="The Angel Cheque", ability_text="Garage Angel retired at 33, drove up in a gold sports car, saw the genius in the garage, and wrote the cheque that kept the lights on. At the top of each Ante, deposits $8 into your cash reserves — no conditions, no scaling, just a reliable cheque arriving like clockwork so you can focus on the product.", rarity="Uncommon", salary=10, hint="flat economy — generates $8 Cash at the s…", effect={type="economy", scaling="flat", hook="before", primitive_hint="dollars", engine_status="executable", magnitude="8", ke_complement=false}, dsl={hook="setting_blind", once=true, once_scope="ante", ops={{k="grant", what="cash", amount=8}}}},
  {key="f_mira-murati", effect_brief="+2 Rev/AI card scored; doubled if 3+ Layers", set="Founder", name="72-Hour Fuse", short="Fuse", ability_name="Research-to-Revenue Bridge", ability_text="72-Hour Fuse turns raw research capability into monetisable product faster than anyone else in the room. For each AI-layer card that contributed Users to the current hand's score, gain +2 Rev after scoring. This reward is doubled if you have 3 or more distinct Layers in play — AI only creates ARR when embedded in a complete, user-facing system.", rarity="Uncommon", salary=10, groups={"ex-openai-diaspora"}, hint="+Rev scaling from AI-layer User density", effect={type="plus_mult", scaling="flat", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0, coef=2, per="cards_of_layer", layer="AI"}, {k="scale", field="mult", base=0, coef=2, per="cards_of_layer", layer="AI", gate={g="count", per="distinct_layers", op=">=", val=3}}}}},
  {key="f_mitch-kapor", effect_brief="×(Coverage−2) Rev at 3+ Layers; +2 Users per Ship this run", set="Founder", name="Fork-Dropper", short="Fork-Dropper", ability_name="Killer App", ability_text="Fork-Dropper beats the incumbent not by doing one thing better but by integrating spreadsheet, charts, and database into one suite — breadth of integration is the moat. When you Ship a hand whose App Type covers 3 or more distinct Layers, the scored ARR gains ×(Coverage − 2) bonus Rev: a 3-Layer stack ×1, 4-Layer ×2, full 5-Layer ×3. And the integrated install base compounds: +2 Users for every blind you have Shipped this run, stacking quietly (reset only when a blind is lost).", rarity="Uncommon", salary=10, groups={"New England Apple Tree", "PayPal-adjacent connector network"}, mafia=true, hint="+Rev scaling by Coverage (distinct Layer…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=-2, coef=1, per="distinct_layers", gate={g="count", per="distinct_layers", op=">=", val=3}}, {k="acc", field="chips", base=0, coef=2, step="ship", state="suite", reset_on={"blind_lost"}}}}},
  {key="f_morris-chang", effect_brief="End of round: +$2 Cash per Infra card in your deck", set="Founder", name="Tide-Taking Foundry", short="Foundry", ability_name="Crisis R&D Covenant", ability_text="Tide-Taking Foundry treats its process-node lead as a structural asset: the deeper your installed Infra base, the more capacity it spins off as cash. At the end of every round, earn $2 for each Infra card in your deck. As you adopt more Infra over the run, this end-of-round payout compounds into the backbone of your economy.", rarity="Rare", salary=20, hint="Permanently tracks a 'Node Floor' counter…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="2 * node_floor_counter (counter += 1 per Infra card played,…", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="cash", per="deck_layer_count", layer="Infra", coef=2}}}},
  {key="f_mustafa-suleyman", effect_brief="Narrow blind clear: +$4 Cash, +2 Rev next blind", set="Founder", name="Reverse Bandit", short="Bandit", ability_name="Reverse Acquihire", ability_text="The Reverse Bandit turns a hair's-breadth escape into institutional leverage — the deal that looked like a near-loss functions as a promotion. Whenever you clear a blind narrowly (final ARR is 1.0–1.3x the target), he triggers once: receive $4 Cash and carry a +2 Rev bonus into your next blind.", rarity="Uncommon", salary=10, groups={"deepmind-diaspora", "ex-google-ai-diaspora", "deepmind-founders", "inflection-ai-founders"}, hint="Cash generation + scaling Rev on the nex…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="blind_won", gate={g="and", gs={{g="arr_ratio", stage="pre_after", op=">=", val=1.0}, {g="arr_ratio", stage="pre_after", op="<", val=1.3}}}, once=true, once_scope="blind", ops={{k="grant", what="cash", amount=4}, {k="arm", field="mult", base=2}}}},
  {key="f_nando-de-freitas", effect_brief="+15 Users each round held, ramping to +120", set="Founder", name="Scale Prophet", short="Prophet", ability_name="The Game Is Over", ability_text="Scale Prophet bets that bigger models plus more data beat clever tricks every time — and doubles down every round. Each round he stays hired, Users gain a stacking +15. The bet keeps compounding round after round until the step-change arrives and the curve plateaus at +120 Users.", rarity="Common", salary=5, groups={"oxford-ai-cluster", "deepmind-alumni"}, hint="scaling-over-time (+Users, grows each rou…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0, coef=15, step="round", max=8, when="post", state="plus_chips", reset_on={"selling_self"}}}}},
  {key="f_nat-friedman", effect_brief="Pays own Salary; +2 Cash/round +1 per ai-grant founder", set="Founder", name="Scroll Unlocker", short="Unlocker", ability_name="Insurgent Bet", ability_text="Scroll Unlocker backs the insurgent bet. While hired he funds his own seat: payroll relief equal to his Salary (he never costs you). Each round held he also generates +2 Cash, plus +1 Cash for every founder you hold from the same open-source/AI-grant lineage (ai-grant) — the more of the crew you stack, the more the bet pays.", rarity="Common", salary=5, groups={"ex-github", "ai-grant"}, hint="scaling-over-time + conditional Cash gene…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={passive={what="salary", amount=2}, hook="end_of_round", ops={{k="grant", what="cash", amount=2, per="count_group", group="ai-grant", coef=1}}}},
  {key="f_neil-shen", effect_brief="+×0.15 Rev per new Layer played (max ×1.75)", set="Founder", name="Midas Recount", short="Recount", ability_name="24 Months Early", ability_text="Midas Recount spots the trajectory 24 months before anyone else notices, runs the math, and recalibrates the price accordingly. Each time you score a hand containing a Layer type never played before this run, ×Rev increases permanently by ×0.15. A deck that spans all five Layers reaches ×1.75 — the compounded return of seeing every wave early.", rarity="Uncommon", salary=10, hint="Permanently x1.15 Rev for each distinct…", effect={type="xmult", scaling="scaling_persistent", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.15 * distinct_layers_ever_played", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="x_mult", base=1.0, coef=0.15, per="distinct_layers_seen_run"}}}},
  {key="f_nick-frosst", effect_brief="+$12 Cash once: 3 AI-engineer-wave Founders hired", set="Founder", name="Calmest Heretic", short="Heretic", ability_name="Sovereign Deployment", ability_text="Calmest Heretic tells regulated enterprises to stop renting access and own the infrastructure outright — and the contract that follows changes everything. The first time you end a round while holding 3 or more Founders from the AI-engineer wave, immediately gain $12 Cash. Triggers once per run: like a signed enterprise deal, it only happens once, but it is the deal that rewrites the runway.", rarity="Common", salary=5, groups={"hinton-diaspora", "toronto-ai-cluster"}, hint="One-time $Cash burst when your lineup cro…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="12 (one-time, triggers once per run when AI-layer founder c…", ke_complement=false}, dsl={hook="after", gate={g="has_group", group="ai-engineer-wave", val=3}, ops={{k="scale", field="dollars", base=12.0, coef=0}}, once=true, once_scope="run"}},
  {key="f_nicola-guarino", effect_brief="×1.2 Rev per Layer; clash = −10 Users", set="Founder", name="Category Cop", short="Cop", ability_name="Ontological Alignment", ability_text="Category Cop validates your hand before scoring: for each distinct Layer present, applies a ×1.2 Rev multiplier stacking multiplicatively. A 2-Layer hand gets ×1.44; 3 Layers ×1.73; 4 Layers ×2.07; all 5 Layers ×2.49. The catch: if any two cards belong to the same Layer AND the same Compatibility cluster, the bonus for that Layer is lost and replaced with a −10 Users penalty. Well-structured, ontologically distinct stacks are rewarded; conceptual redundancy is punished.", rarity="Uncommon", salary=10, groups={"formal-ontology-founders", "semantic-web-theorists"}, hint="×Rev scaling with stack diversity (disti…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.2, per="distinct_layers"}, {k="clash_tax", field="chips", per=10}}}},
  {key="f_niki-parmar", effect_brief="Stacking +12 Users each round held; resets on Pivot/fold", set="Founder", name="Loss-Curve Oracle", short="Oracle", ability_name="Tensor2Tensor", ability_text="Loss-Curve Oracle iterates relentlessly through model variants, holding the line round after round. Each round this founder is held adds a stacking +12 Users (round 1: +12, round 2: +24, round 3: +36, and onward). The streak resets to zero if you ever Pivot or fold a blind — momentum only compounds while you keep shipping.", rarity="Uncommon", salary=10, groups={"transformer-paper-authors", "ex-google-brain-diaspora", "transformer-eight", "ex-google-ai-diaspora"}, hint="scaling-over-time + conditional +Users", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0.0, coef=12, state="plus_chips", when="post", step="round", reset_on={"discard","blind_lost"}}}}},
  {key="f_noah-glass", effect_brief="Lone founder: dissolves all Layer mismatches, 1st hand/round", set="Founder", name="Unshaken Hand", short="Hand", ability_name="Nobody Heard the Name", ability_text="Unshaken Hand is the quiet connective tissue — the one who makes incompatible pieces gel, and takes no credit. While he is your ONLY founder, the first hand you ship each round has all of its Layer mismatches dissolved, so every tech card contributes its full Users. Once per round.", rarity="Common", salary=5, groups={"Odeo crew", "Twitter founders", "twitter-cofounders"}, hint="once per round, if no other founder trigg…", effect={type="utility", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="waive Layer mismatch penalty on 1 tech card this hand; fire…", ke_complement=false}, dsl={hook="before", gate={g="count", per="others", op="==", val=0}, ops={{k="clear_clash", amount="all"}}, once=true, once_scope="blind"}},
  {key="f_noam-shazeer", effect_brief="AI cards ×1.5 Rev; +×0.25/round held", set="Founder", name="Floor-Dropper", short="Floor-Droppe", ability_name="Substrate Rewrite", ability_text="Floor-Dropper re-architects the layer everything runs on, then walks out when the institution stalls — and the institution pays billions to get him back. Every card in the AI Layer scores with ×1.5 Rev instead of its base Rev. For each consecutive round held, that multiplier grows by ×0.25. If the active Market is Enterprise or Consumer AI, the multiplier applies to Backend cards as well.", rarity="Legendary", salary=40, groups={"transformer-eight", "ex-google-ai-diaspora", "transformer-authors"}, hint="×Rev (AI-layer architecture unlock; scal…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="individual", gate={g="or", gs={{g="card_layer", layer="AI"}, {g="and", gs={{g="card_layer", layer="Backend"}, {g="or", gs={{g="market", attr="industry", value="enterprise"}, {g="market", attr="audience", value="B2C"}}}}}}}, ops={{k="scale", field="x_mult", base=1.5, coef=0.25, per="rounds_held"}}}},
  {key="f_nolan-bushnell", effect_brief="First hand each round: x(2 + 0.5/other Founder) Rev", set="Founder", name="$50,000 No", short="No", ability_name="This Time I Say Yes", ability_text="The instinct was always right — he could spot the spark in a misfit teenager the moment they walked in. Once the team is in the room, the bet pays off: the first scored hand each round, score x(2 + 0.5 per other Founder on your roster) Rev. The bigger the team you've assembled, the bigger the bet — and saying yes is the whole point.", rarity="Uncommon", salary=10, groups={"University of Utah"}, hint="xmult burst when you hire a Founder this…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="2 + 0.5 * founders_on_roster", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=2.0, coef=0.5, per="others"}}, once=true, once_scope="blind"}},
  {key="f_norman-foster", effect_brief="+2 Users to all Infra cards on Ship; ×2 after lo", set="Founder", name="Spaceship Whisperer", short="Whisperer", ability_name="Revision Cycle", ability_text="Every project needs a crisis. He worked revision after revision in close collaboration with demanding clients, and when the breaking point finally arrived the solution was always cleaner than anything the original brief imagined. Each time you Ship a hand that includes at least one Infra card, every Infra card in your deck permanently gains +2 Users. If the previous blind was lost, this round's Infra bonus is doubled — the setback becomes the structural breakthrough.", rarity="Common", salary=5, hint="scaling-over-time (Infra depth compounds…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", gate={g="layer_present", layer="Infra"}, ops={{k="acc", field="chips", base=0, coef=2, state="infra_ship", when="post", step="ship"}}}},
  {key="f_ora-lassila", effect_brief="Name edge: waives clash; +0.5× per distinct Laye", set="Founder", name="Predicate Priest", short="Priest", ability_name="Open World Assumption", ability_text="He realized that the arrow between two things is more powerful than either thing alone. Give any relationship a name — 'powers', 'integrates-with', 'feeds-into' — and two nodes that could never talk suddenly share a fact forever. Once per round you may name a Predicate between any two Layer cards in your hand that would otherwise be incompatible; those cards score as fully compatible for this Ship. Named edges are sticky: the compatibility bonus persists in future rounds even without this card in play. In addition, gain +0.5× Rev for each distinct Layer present in the scored hand.", rarity="Uncommon", salary=10, groups={"w3c-advisory-board", "semantic-web-founders"}, hint="Compatibility (interop) + ×Rev scaling w…", effect={type="utility", scaling="flat", hook="joker_main", primitive_hint=nil, engine_status="data_only", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="clear_clash", amount="all"}, {k="scale", field="x_mult", base=1.0, coef=0.5, per="distinct_layers"}}}},
  {key="f_palmer-luckey", effect_brief="Overkill ARR -> Cash 1:1; next round's App starts +2 Rev", set="Founder", name="Flip-Flop Warlord", short="Warlord", ability_name="World Gun Store", ability_text="He built first and collected later — arriving at the competition with a finished product when everyone else showed up with a budget request. Whenever you beat a blind's target ARR, all of the excess converts to Cash at a 1:1 rate instead of being wasted. And because his capability always ships ahead of demand, the next App Type you play next round comes pre-loaded with +2 Rev.", rarity="Uncommon", salary=10, hint="Cash generation / overkill ARR conversion…", effect={type="economy", scaling="conditional_burst", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="grant", what="cash", per="overkill", coef=1, gate={g="overkill", op=">", val=0}}, {k="arm", field="mult", base=2}}}},
  {key="f_patrick-collison", effect_brief="Backend+Infra hand: clears clashes, +1 hand size", set="Founder", name="Seven-Line Prodigy", short="Prodigy", ability_name="Cut-and-Paste, You're Live", ability_text="Seven lines. Cut and paste. You're live. The whole point was to compress weeks of byzantine setup into a snippet anyone could drop in — and once it was in, it just worked. This ability fires once per ante: the moment you land a hand with at least one Backend card AND at least one Infra card, every compatibility clash on your played cards this hand is erased and your hand size grows by +1 for all remaining hands in the ante. A single well-assembled hand unlocks the whole stack.", rarity="Rare", salary=20, hint="utility — first time this ante you play a…", effect={type="utility", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 hand-size increase + clash-clear; triggers once per ante…", ke_complement=false}, dsl={hook="before", once=true, once_scope="ante", gate={g="and", gs={{g="layer_present", layer="Backend"}, {g="layer_present", layer="Infra"}}}, ops={{k="clear_clash", amount="all"}, {k="gen", kind="hand_size", amount=1}}}},
  {key="f_patrick-esser", effect_brief="First Ship: clear all clashes + permanent +10% Margin", set="Founder", name="Stack Rewriter", short="Rewriter", ability_name="Bidirectional Attention Bri…", ability_text="A bidirectional-attention bridge between two representation spaces that previously couldn't coexist. The first hand you Ship, every compatibility clash in that hand is nullified for the score — and the architectural unlock pays off forever: your Margin permanently rises by 10% for the rest of the run. Fires once per run.", rarity="Uncommon", salary=10, groups={"compvis-group", "stable-diffusion-diaspora"}, hint="utility (conditional_burst): once per run…", effect={type="utility", scaling="conditional_burst", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="1 clash nullified (permanent edge removal); triggers once p…", ke_complement=false}, dsl={hook="before", once=true, once_scope="run", ops={{k="clear_clash", amount="all"}, {k="grant", what="margin", amount=0.1}}}},
  {key="f_paul-allen", effect_brief="+×0.3 Rev per new Layer discovered (cap ×1.5)", set="Founder", name="Octal Stowaway", short="Stowaway", ability_name="Loader Routine", ability_text="At 30,000 feet, with no hardware in hand and the demo an hour away, he grabbed a notepad and hand-assembled 21 lines of machine code from memory — the bootstrap that made everything above it possible. Each time you play a hand containing a tech card from a Layer you have never played before this run, gain +0.3× Rev permanently. Caps naturally at +1.5× across all five Layer discoveries, but rewards deliberate multi-layer deck building — the loader locks in, the stack compounds.", rarity="Rare", salary=20, groups={"lakeside-programming-group"}, hint="xmult that grows permanently with each di…", effect={type="xmult", scaling="scaling_persistent", hook="after", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.3 * distinct_layers_seen", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="x_mult", base=1.0, coef=0.3, per="distinct_layers_seen_run"}}}},
  {key="f_paul-buchheit", effect_brief="Each new-to-run Layer retriggers all scoring cards once", set="Founder", name="Friday Arsonist", short="Arsonist", ability_name="One-Day Proof", ability_text="One Friday afternoon, a throwaway demo of the thing everyone insisted would never work. Whenever you Ship a hand that breaks into Layers your product has never used before, the demo lights up: every scoring card is re-scored once for each brand-new Layer in that hand (you have 5 Layers, so up to 5x on a true greenfield hand). Hands that only re-use Layers you have already shipped get no encore — only branching into unfamiliar territory earns the compounding retrigger.", rarity="Uncommon", salary=10, hint="retrigger: the first tech card played fro…", effect={type="retrigger", scaling="conditional_burst", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="1 retrigger per first-play of each distinct Layer not yet u…", ke_complement=false}, dsl={retrigger={base=0, coef=1, per="new_layers"}}},
  {key="f_paul-graham", effect_brief="While hired: +2 Founder slots (room for the cohort)", set="Founder", name="Glop Cook", short="Cook", ability_name="Demo Day Batch", ability_text="He ran startups like a compiler runs code — in parallel, same conditions, $15k checks at a kitchen table, 6% equity, network effects emerging on their own. A batch needs room to compound. While hired, your roster has +2 Founder slots — bring him in early and the cohort fills the bench by IPO.", rarity="Rare", salary=20, hint="Generates Founder cards into your roster,…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 + antes_cleared (Founder options offered per batch)", ke_complement=false}, dsl={passive={what="founder_slots", amount=2}}},
  {key="f_peter-drucker", effect_brief="Removes all clashes; +1 Joker slot (lean team on", set="Founder", name="My Own Secretary", short="Secretary", ability_name="Getting The Right Things Do…", ability_text="Knowledge is the one decisive factor of production — and knowledge workers are only effective when they get the right things done, not merely busy things. He worked alone: one man, a typewriter, a wicker chair, no staff. While hired, every tech card and every Founder simply works with everything — all Layer compatibility clashes and support-slot penalties are removed. He costs no Joker slot of his own and grants +1 effective Joker slot, but only while your founder lineup stays lean. He owns no score lever; he only ever makes the founders around him work.", rarity="Legendary", salary=40, groups={"management-theorists", "drucker-forum-lineage"}, hint="Utility: removes all compatibility clashe…", effect={type="utility", scaling="flat", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="clears all compatibility clashes; +1 effective Joker slot w…", ke_complement=true}, dsl={ hook="before", ops={ {k="clear_clash", amount="all"} }, passive={ what="founder_slots", amount=1 } }},
  {key="f_peter-thiel", effect_brief="Top-Users card retriggered; +1 rep per redundant card", set="Founder", name="Power-Law Pawnbroker", short="Pawnbroker", ability_name="Competition Is For Losers", ability_text="Competition is for losers. One outlier carries the fund: the single highest-Users card in the played hand is treated as a monopoly and retriggered. The more you double down on one category instead of spreading thin (every card beyond one-per-Layer), the more that winner compounds — +1 extra retrigger of the top card per redundant card.", rarity="Rare", salary=20, groups={"paypal-mafia", "stanford-review", "founders-fund-leadership"}, mafia=true, hint="Revenue-per-user (×Rev) via contrarian a…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", retrigger={base=1, coef=1, per="redundant_cards"}, retrigger_target="highest"}},
  {key="f_pierre-omidyar", effect_brief="+10 Users per distinct App Type Shipped this run", set="Founder", name="Nickel-Taped Oracle", short="Oracle", ability_name="Trust Receipt", ability_text="He didn't need the capital — the first payments arrived taped to index cards, nickels and dimes in crumpled envelopes. The real asset was the permanent public record: every distinct App Type you have ever Shipped leaves a trust receipt that future strangers can read, and the feedback graph keeps making itself. Each scoring hand gains +10 Users for every distinct App Type Shipped this run — a slow, compounding network that never leaves.", rarity="Uncommon", salary=10, groups={"iranian-diaspora-valley"}, hint="generation — each distinct App Type Shipp…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 Trust Receipt card per distinct App Type Shipped (max ~12…", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="chips", base=0, coef=10, per="distinct_app_types_shipped"}}}},
  {key="f_pieter-abbeel", effect_brief="3+ AI cards: retrigger top card, +1/round held", set="Founder", name="Founder Farm", short="Farm", ability_name="Apprenticeship Learning", ability_text="One well-chosen demonstration generalizes across the whole task space. While Founder Farm is on your team, your demonstration library deepens every round he is held. When you Ship a hand containing 3 or more distinct AI-layer cards, the single highest-Users card in that hand is re-scored an extra (1 + rounds_held) times — its Users contribution counted again for every demonstration in the library. The longer you hold him, the larger the library, the harder that one example generalizes.", rarity="Uncommon", salary=10, groups={"uc-berkeley-ai-lab", "bair-lab"}, hint="Scaling-over-time + spawning bonus (Copy/…", effect={type="generation", scaling="scaling_persistent", hook="joker_main", primitive_hint=nil, engine_status="data_only", magnitude="", ke_complement=false}, dsl={retrigger={base=1, coef=1, per="rounds_held"}, retrigger_target="highest", gate={g="count", per="cards_of_layer", layer="AI", op=">=", val=3}}},
  {key="f_pony-ma", effect_brief="Once/run: xRev per Layer if you clear target w/o blowout", set="Founder", name="Midnight Cannibalist", short="Cannibalist", ability_name="Life or Death Window", ability_text="He gave the go-ahead that very night, knowing the new product would cannibalize the cash cow. Once per run, the first time you Ship a hand that clears the round's target without blowing past it (final ARR under 1.5x the target), this founder fires: that hand's Rev is multiplied by x(1 + 0.5 x distinct Layers in hand). The sacrifice has to be genuine, a restrained play, and the trigger clears for the rest of the run once fired.", rarity="Rare", salary=20, hint="xMult burst when you voluntarily score be…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.5 * distinct_layers_in_hand", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op="<", val=1.5}, ops={{k="scale", field="x_mult", base=1.0, coef=0.5, per="distinct_layers"}}, once=true, once_scope="run"}},
  {key="f_ramanathan-guha", effect_brief="+×0.5 Rev/Layer; removes 1 clash/ante", set="Founder", name="Schema Whisperer", short="Whisperer", ability_name="Common Vocabulary", ability_text="He convinced four competing search engines to publish a single shared vocabulary — no one owned it, so everyone could trust it, and within a decade it was embedded across a sixth of the web. When you Ship a hand, for each distinct Layer beyond the first gain +×0.5 Rev (a 5-Layer hand earns +×2.0 Rev; narrow stacks get almost nothing). Additionally, once per ante choose any two Layer cards in your deck with a Compatibility penalty against each other; that penalty is removed for the rest of the run.", rarity="Uncommon", salary=10, groups={"cyc-project", "w3c-rdf-working-group", "schema-org-founders"}, yc=true, hint="×Rev scaling with Layer diversity (inter…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=0.5, coef=0.5, per="distinct_layers"}}}},
  {key="f_raquel-urtasun", effect_brief="Banks overkill Users; +1/overkill/round", set="Founder", name="World Inside The World", short="World", ability_name="Closed-Loop Simulator", ability_text="Real-world data is mostly uninteresting, and the edge cases that matter are too rare to collect on any road. Build a simulator good enough that synthetic signal is indistinguishable from the real thing — then generate adversarial scenarios at scale. At the end of each round, any ARR scored above the blind's required threshold is converted into bonus Users banked for the next round rather than wasted. The bank grows by +1 User per overkill ARR point each round this founder is held; each distinct Infra card in the current hand adds ×1 to the conversion rate.", rarity="Common", salary=5, groups={"toronto-ai-cluster"}, hint="scaling-over-time / conditional overkill…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="end_of_round", ops={{k="arm", field="chips", base=0, coef=1, per="overkill"}}}},
  {key="f_ray-ozzie", effect_brief="+8 Users per unplayed card in hand, on Ship", set="Founder", name="Patient Replicator", short="Replicator", ability_name="Replica Cascade", ability_text="He wrote the spec before any network existed — a product built for a world that hadn't arrived yet. The key bet: don't require a live connection. Work offline, merge state later, and when the connection finally comes the whole userbase floods in at once. Each card you hold back (do NOT play) buffers deferred state; when you Ship, that state syncs — gain +8 Users for every unplayed card in hand before scoring. The more you hold in reserve, the bigger the sync cascade.", rarity="Common", salary=5, hint="+Users burst on Ship equal to 8 × accumul…", effect={type="plus_chips", scaling="conditional_burst", hook="before", primitive_hint="chips", engine_status="executable", magnitude="8 * sync_tokens (tokens capped at 5, resets on Ship)", ke_complement=false}, dsl={hook="before", ops={{k="scale", field="chips", base=0, coef=8, per="unplayed_cards"}}}},
  {key="f_reed-hastings", effect_brief="×Rev +0.2 each ante; grows to ×2.6", set="Founder", name="Patient Streamer", short="Streamer", ability_name="Wait for the Curve", ability_text="He raised the funding knowing the technology was impossible at the time. Then he waited — watching the bandwidth curves, knowing exactly where they were going, turning down every acquisition offer while the infrastructure caught up to the thesis. Every time you complete an ante, this card's ×Rev permanently increases by +0.2×, starting at ×1.0. Holds him the whole run and you reach ×2.6 by the final stage. Sell him early and the compounding stops.", rarity="Uncommon", salary=10, hint="xMult that permanently grows by +0.2x eac…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.2 * antes_completed", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=0.8, coef=0.2, per="ante"}}}},
  {key="f_reid-hoffman", effect_brief="While hired: +2 founder slots (wider network bench)", set="Founder", name="BOOM-Flag Broker", short="Broker", ability_name="You Two Should Meet", ability_text="He was the human switchboard — the connector who put the right two people in a room and then stepped back while history happened. His only weapon in the toughest negotiation he ever faced was a toy gun that popped a flag reading BOOM. While he runs the network, you keep +2 founder slots — a wider room, more of the right people kept close at once.", rarity="Uncommon", salary=10, groups={"paypal-mafia", "sf-social-networking-mafia", "silicon-valley-investor-network", "inflection-ai-founders", "greylock-partners"}, mafia=true, hint="Generates founders into the shop — each r…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="introductions += 1 each blind; +1 founder offered in shop p…", ke_complement=false}, dsl={passive={what="founder_slots", amount=2}}},
  {key="f_richard-branson", effect_brief="On blind win: deal 1 free Tech per distinct Market entered", set="Founder", name="Nine-Day Heist", short="Heist", ability_name="Crash the Incumbent", ability_text="Crash the Incumbent. Spot the fat, complacent market the incumbents have left wide open, plant the flag, and spin a whole new business out of the brand alone. When you win a blind, deal 1 free Tech card for every distinct Market your run has entered — the more lanes you've crashed, the more your brand prints product.", rarity="Common", salary=5, hint="generation — each new Market lane entered…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 Tech card added to shop pool + 1 immediate Tech card deal…", ke_complement=false}, dsl={hook="blind_won", ops={{k="gen", kind="tech_card", per="distinct_markets_seen_run", base=0, coef=1}}}},
  {key="f_richard-stallman", effect_brief="+1 Rev each round hired, compounding up to +3 Rev", set="Founder", name="Copyleft Prophet", short="Prophet", ability_name="Copyleft Clause", ability_text="One blocked modification, a decade-long crusade. Each Ship while the Copyleft Prophet is in play, your stack spreads a little further into the commons — every round he is hired adds +1 Rev to scoring, compounding up to +3 Rev. Open code is viral: it only grows.", rarity="Uncommon", salary=10, groups={"mit-ai-lab", "tech-model-railroad-club"}, hint="viral ARR multiplication (scaling-over-ti…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0.0, coef=1.0, max=3, step="ship", when="post", state="copyleft", reset_on={"selling_self"}}}}},
  {key="f_robert-metcalfe", effect_brief="×Rev burst on Infra+Backend hand (once/run)", set="Founder", name="Square-Law Swallower", short="Swallower", ability_name="Blender Keynote", ability_text="He predicted the internet would collapse — it didn't — and at his next keynote he blended and ate the printed column in front of a thousand attendees, turning humiliation into a standing ovation. Once per run, the first hand you play that covers both Infra and Backend layers simultaneously triggers a one-time xMult burst equal to ×(1 + 0.5 × distinct layers in hand). Outside that window the Square-Law Swallower sits quietly, waiting for the network moment to arrive.", rarity="Rare", salary=20, hint="xmult conditional burst: once per run, wh…", effect={type="xmult", scaling="conditional_burst", hook="individual", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.5 * distinct_layers_in_hand (fires once per run, only…", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.5, per="distinct_layers"}}, gate={g="and", gs={{g="layer_present", layer="Infra"}, {g="layer_present", layer="Backend"}}}, once=true, once_scope="run"}},
  {key="f_robert-morris", effect_brief="+2 Rev per redundant card; +15 Users if any Layer doubled", set="Founder", name="Accidental Arsonist", short="Arsonist", ability_name="It Will Never Work", ability_text="The most overqualified sysadmin in history — a man who once accidentally crashed a slice of the early internet — became startup-land's most rigorous gatekeeper. He rewards a stack with real depth and punishes a pile of one-off bolt-ons. When you Ship, gain +2 Rev for each redundant card (every Tech card past the first in its Layer). And if your hand isn't all loose singletons — at least one Layer is doubled up — the stack passes his filter for +15 Users.", rarity="Common", salary=5, hint="conditional scoring + ARR protection", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0, coef=2, per="redundant_cards"}, {k="scale", field="chips", base=15, coef=0, gate={g="not", g1={g="all_distinct_layers"}}}}}},
  {key="f_robert-noyce", effect_brief="+0.05 permanent ×Rev per Layer played, each round held", set="Founder", name="Loss-Leader Prophet", short="Prophet", ability_name="Sell Below Cost", ability_text="The Loss-Leader Prophet floods the market by selling below cost — the wider his coverage, the deeper the flywheel bites. Each round you hold him, his ×Rev permanently ratchets up by +0.05 for every distinct Layer played that round. Cover the whole stack early and hold him: the floods compound into a permanent moat.", rarity="Legendary", salary=40, groups={"traitorous-eight", "fairchildren"}, hint="xMult grows permanently each round as cum…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.25 * distinct_layers_in_played_hand + 0.1 * rounds_…", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.0, coef=0.05, state="prophet", step="round", inc_per="distinct_layers", when="post", max=80}}}},
  {key="f_robin-rombach", effect_brief="+1 Rev/round with AI card played", set="Founder", name="Latent Squeezer", short="Squeezer", ability_name="8× Latent Dividend", ability_text="The breakthrough was obvious once you saw it: compress the image first with an autoencoder, then run the hard math in that tiny latent space — the same quality at a fraction of the compute. The Latent Squeezer quietly stacks: at the end of each round in which one or more AI-layer Tech cards were played, this card permanently gains +1 Rev. The dividend is small but compounds across the run. A second founder from the same research lineage in play doubles the per-round gain to +2 Rev.", rarity="Uncommon", salary=10, groups={"compvis-group", "stable-diffusion-diaspora"}, hint="Permanently adds +Rev each round at leas…", effect={type="plus_mult", scaling="scaling_persistent", hook="after", primitive_hint="mult", engine_status="executable", magnitude="1 * rounds_ai_card_played (doubles to 2 if stable-diffusion…", ke_complement=false}, dsl={hook="after", gate={g="layer_present", layer="AI"}, ops={{k="acc", field="mult", base=0.0, coef=1.0, state="latent_div", when="post", step="round"}}}},
  {key="f_ron-brachman", effect_brief="Clears 1 clash/hand; +2 Rev/clean Layer", set="Founder", name="IS-A Untangler", short="Untangler", ability_name="Subsumption Classifier", ability_text="He noticed researchers were using the same link notation to mean five completely different things simultaneously — and nobody had noticed. The IS-A Untangler brought order: while in play, one Layer card per hand that would normally incur a compatibility penalty is automatically re-classified into a role it does fit, erasing the penalty and restoring its base Users value. After the override, gain +2 Rev per distinct Layer present in non-penalty positions, up to a maximum of +10 Rev.", rarity="Uncommon", salary=10, groups={"aaai-presidents", "acm-fellows", "ieee-fellows", "aaai-fellows", "aaas-fellows"}, hint="Compatibility override (removes layer-mis…", effect={type="utility", scaling="flat", hook="joker_main", primitive_hint=nil, engine_status="data_only", magnitude="", ke_complement=true}, dsl={hook="before", ops={{k="clear_clash", amount=1}, {k="scale", field="mult", base=0, coef=2, per="distinct_layers"}}}},
  {key="f_ron-conway", effect_brief="Cash-out: +$2 per Founder hired this run", set="Founder", name="Human Router", short="Router", ability_name="The Partner Spreadsheet", ability_text="The moment you fire off an 11pm distress email, 'AM ON IT' comes back within two minutes. The Human Router's Rolodex is yours the day you sign: every Founder on your team is a warm intro that keeps paying off. At each cash-out, earn $2 Cash for every Founder you have hired this run — the more relationships you bank, the more deal-flow the network throws back at you.", rarity="Uncommon", salary=10, hint="When you hire a Founder, instantly add 2…", effect={type="generation", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="2 Founder cards added to shop per hire event", ke_complement=false}, dsl={hook="pre_cash_out", ops={{k="grant", what="cash", per="founders_hired_this_run", coef=2}}}},
  {key="f_ross-perot", effect_brief="Retriggers highest-Users card once each Ship", set="Founder", name="77th Door", short="Door", ability_name="Anchor Contract", ability_text="Seventy-six doors slammed shut before the seventy-seventh opened. 77th Door locks onto your single foothold: every Ship, the highest-Users Tech card in your hand has its Users contribution retriggered once -- the one card that compounds into the whole enterprise.", rarity="Common", salary=5, hint="scaling-over-time + conditional +Users", effect={type="retrigger", scaling="conditional_burst", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="", ke_complement=false}, dsl={retrigger=1, retrigger_target="highest"}},
  {key="f_rupert-murdoch", effect_brief="Content hand: +Cash =5% ARR; +1 Rev/Ship (perm)", set="Founder", name="Wrong Network", short="Network", ability_name="Tabloid Flywheel", ability_text="Wrong Network runs content as a cash engine, harvests the profits, and buys prestige that compounds — until the day it bets on the wrong network. On any content-first hand (anything but a pure Infra/Backend play), it skims +Cash equal to 5% of that hand's ARR, and each such Ship permanently adds +1 Rev to this founder. Never fires on Infra/Backend hands.", rarity="Common", salary=5, hint="Cash generation + acquisition scaling", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="not", g1={g="app_type_in", names={"Infra/Backend Platform"}}}, ops={{k="scale", field="dollars", base=0, coef=0.05, per="running_arr", stage="pre_after"}, {k="acc", field="mult", step="ship", base=0, coef=1, state="flywheel"}}}},
  {key="f_sabeer-bhatia", effect_brief="Retrigger all Users +1 per round held", set="Founder", name="Decoy Dealer", short="Dealer", ability_name="Viral Postscript", ability_text="Every message the product sent carried one line at the bottom — a free ad that forwarded itself. The Decoy Dealer's viral loop compounds the longer it runs: each time you Ship a hand, every card in that hand retriggers its Users value once as a 'forwarded message,' plus one extra retrigger for every round this founder has been held. The more rounds the postscript keeps shipping, the wider it spreads.", rarity="Uncommon", salary=10, hint="+Users (Users) per Ship — scaling over ti…", effect={type="retrigger", scaling="scaling_persistent", hook="individual", primitive_hint="jokers.repetitions", engine_status="executable", magnitude="", ke_complement=false}, dsl={retrigger={base=1, coef=1, per="rounds_held"}}},
  {key="f_sam-altman", effect_brief="+0.05 ×Rev/hired founder each round", set="Founder", name="Five-Day Phoenix", short="Phoenix", ability_name="Loyalty Cascade", ability_text="He walked back through the same glass doors five days after being marched out of them, visitor lanyard still on, phone buzzing with the open letter — because the headcount was always his. Loyalty Cascade: each round the Five-Day Phoenix is held, he gains +0.05 xMult for every other Founder currently hired. The bonus accumulates permanently for the rest of the run; the larger the team rallied around him, the steeper the curve compounds.", rarity="Legendary", salary=40, groups={"openai-founders", "y-combinator-alumni", "ex-openai-diaspora"}, yc=true, hint="Permanent Xmult that snowballs from the s…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="x_mult += 0.05 * other_hired_founders each round held (perm…", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="x_mult", base=1.0, coef=0.05, inc_per="others", step="round", when="post", max=80}}}},
  {key="f_sam-mccandlish", effect_brief="×Rev +0.15 per Ship; starts ×1.0", set="Founder", name="Thermometer Prophet", short="Prophet", ability_name="Noise Scale Horizon", ability_text="The insight came from physics: noisy gradients in hard training tasks are like a high-temperature system, and the noise scale is the thermometer that tells you how far the curve will go. Each time you Ship, the Thermometer Prophet reads one more decade off the log-log plot, permanently increasing his xMult by +0.15. Start at ×1.0; modest early, ruthless at scale. You are not guessing the future — you are measuring it.", rarity="Rare", salary=20, groups={"ex-openai-diaspora", "anthropic-founding-team"}, hint="xmult that grows permanently each time a…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1.0 + 0.15 * hands_played_this_run", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.15, per="ships_this_run"}}}},
  {key="f_sandy-lerner", effect_brief="End of round: +1 Tech/distinct Layer in last hand", set="Founder", name="Palace Coup", short="Coup", ability_name="Second Founding", ability_text="Ousted by her own VPs, she walked out with a router in one hand and started over the same week. Second Founding: at the end of every round, the Palace Coup hands you one fresh random Tech card for each distinct Layer in your last shipped product — the broader the stack you built, the bigger the regroup.", rarity="Uncommon", salary=10, hint="on round loss (palace coup), generate 1 f…", effect={type="generation", scaling="conditional_burst", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 tech card per distinct Layer in last played hand (max 5)", ke_complement=false}, dsl={hook="end_of_round", ops={{k="gen", kind="tech_card", per="last_hand_distinct_layers", base=0, coef=1}}}},
  {key="f_scott-cook", effect_brief="1st Ship of run: dissolve all clashes + perm +1 hand size", set="Founder", name="Anomaly Savorer", short="Savorer", ability_name="No Accounting For It", ability_text="Double-entry bookkeeping was invented to catch human arithmetic errors — a problem computers don't have. The Anomaly Savorer deleted a centuries-old constraint because it was solving the wrong problem. No Accounting For It: the first hand you Ship this run, every Layer compatibility clash is silently dissolved (all cards score as fully compatible) and your hand size permanently increases by +1. Fires exactly once per run; the legacy constraint is gone for good.", rarity="Common", salary=5, hint="one-time burst: on first hand with a comp…", effect={type="utility", scaling="conditional_burst", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="1 hand-size increase + clash removal, triggers once on firs…", ke_complement=false}, dsl={hook="before", once=true, once_scope="run", ops={{k="clear_clash", amount="all"}, {k="gen", kind="hand_size", amount=1}}}},
  {key="f_scott-wu", effect_brief="+0.5x Rev per round held (compounds while hired)", set="Founder", name="Buddy Builder", short="Builder", ability_name="Recursive Deploy", ability_text="The Buddy Builder's Recursive Deploy: his agent keeps shipping on its own while you sleep, and the longer he stays hired the more it compounds. Gives +0.5x Rev for every round he has been on the team (1x at hire).", rarity="Common", salary=5, groups={"ioi-gold-medalists", "ai-engineer-wave", "competitive-programming-cohort"}, hint="scaling-over-time (self-referential ARR c…", effect={type="generation", scaling="scaling_persistent", hook="joker_main", primitive_hint=nil, engine_status="data_only", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1, coef=0.5, per="rounds_held"}}}},
  {key="f_sean-parker", effect_brief="While hired: -$8 Salary due every round", set="Founder", name="Hundred-Pre Bandit", short="Bandit", ability_name="One Hundred Pre", ability_text="'No way! We want one hundred pre!' — fired twice before, he wrote the insurance into the bylaws before anyone could move against him. Anti-Dilution: while this Founder is in play, your payroll is permanently cut by $8 each round — hold the line and the Salary bleed never touches you.", rarity="Uncommon", salary=10, groups={"sf-social-networking-mafia"}, mafia=true, hint="Margin / dilution-defense (anti-Salary, v…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={passive={what="salary", amount=8}}},
  {key="f_sergey-brin", effect_brief="+0.25×Rev/rnd; resets to 0 if fired", set="Founder", name="Rollerblade Mathematician", short="Mathematicia", ability_name="Founder Back In The Trenches", ability_text="He returned to the codebase after years away, stripped the approval committees slowing model training, ran 60-hour sprints, and filed his first code change in years — a small config tweak that sent an unmistakable signal. Founder Back In The Trenches: each round the Rollerblade Mathematician is held without being fired, gain +0.25 xMult permanently. If you fire him, the entire accumulated xMult resets to zero and is lost — pull the founder from the trenches and the compounding unravels.", rarity="Rare", salary=20, groups={"googlers"}, hint="permanent xMult that compounds every roun…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="1 + 0.25*rounds_held", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=1.0, coef=0.25, per="rounds_held"}}}},
  {key="f_shane-legg", effect_brief="+12 Rev first time all 5 Layers played", set="Founder", name="Patient Oracle", short="Oracle", ability_name="The 2028 Moment", ability_text="The formal model said generalization only emerges once all environments are covered. He published the prediction, committed to it publicly, and waited without flinching for reality to catch up. The Patient Oracle watches patiently round after round, giving nothing. The moment your played hand first spans all 5 Layers — Frontend, Backend, Data, Infra, AI — he calls it: +12 Rev, triggered exactly once per run.", rarity="Uncommon", salary=10, groups={"deepmind-founders", "deepmind-diaspora", "google-deepmind-leadership"}, hint="one-time +12 Rev burst the first time yo…", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="12 (once per run, on first hand covering all 5 distinct Lay…", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="distinct_layers", op=">=", val=5}, ops={{k="scale", field="mult", base=12.0, coef=0}}, once=true, once_scope="run"}},
  {key="f_simon-suo", effect_brief="+8 Rev if hand covers all 5 Layers", set="Founder", name="Benchmark Setter", short="Setter", ability_name="Top of the Leaderboard", ability_text="Classic infrastructure judo: define the benchmark yourself, then occupy the top of it. The Benchmark Setter rewards completeness: if the cards you play this hand touch every Layer — full-stack coverage, no gaps — grant +8 Rev as a burst for this scoring. Partial coverage earns nothing; the leaderboard only rewards methods that are competitive across all five dimensions.", rarity="Common", salary=5, groups={"ai-engineer-wave"}, hint="when your played hand covers all 5 Layers…", effect={type="plus_mult", scaling="conditional_burst", hook="before", primitive_hint="mult", engine_status="executable", magnitude="8 if distinct_layers_played == 5 else 0", ke_complement=false}, dsl={hook="before", ops={{k="scale", field="mult", base=8.0, coef=0}}, gate={g="count", per="distinct_layers", op=">=", val=5}}},
  {key="f_steve-blank", effect_brief="+1 hand size per new App Type shipped", set="Founder", name="Building Deserter", short="Deserter", ability_name="Four Steps to Epiphany", ability_text="The answer to most startup questions is not in the building — it's outside it. The Building Deserter codified a scientific method: each time you Ship a hand whose App Type you have never Shipped before this run, hand size permanently increases by +1, representing a new customer segment validated. At most +4 can accumulate. Shipping the same App Type repeatedly counts for nothing — repeating the same pitch to the same customer is not learning.", rarity="Uncommon", salary=10, hint="permanently gains +1 hand size each time…", effect={type="utility", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="hand_size += 1 per distinct_app_types_shipped_lifetime, max…", ke_complement=false}, dsl={hook="after", gate={g="count", per="distinct_app_types_shipped", op="<=", val=4}, ops={{k="gen", kind="hand_size", per="new_app_types", base=0, coef=1}}}},
  {key="f_steve-case", effect_brief="Once/Ante: +3 Users per $1 Cash; 2x overkill rebates $0.25/$1", set="Founder", name="Placid Squatter", short="Squatter", ability_name="Free Trial Blitz", ability_text="He squatted a desk near Apple's campus and carpet-bombed the market — floppy disks in cereal boxes, CDs in every magazine and airline seat. Free Trial Blitz: once per Ante, plow the war chest into the top of the funnel — gain +3 Users for every $1 of Cash you hold. If the blitz drives ARR to 2x the funding target or more, the campaign pays for itself: rebate $0.25 per $1 of Cash held.", rarity="Uncommon", salary=10, hint="Users (Users) — aggressive top-of-funnel…", effect={type="plus_chips", scaling="flat", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", once=true, once_scope="ante", ops={{k="scale", field="chips", base=0, coef=3, per="cash"}, {k="grant", what="cash", coef=0.25, per="cash", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}}}}},
  {key="f_steve-chen", effect_brief="Once/run: gain $8 when Cash ≤$3", set="Founder", name="Clause Reader", short="Reader", ability_name="Unlimited Bandwidth Clause", ability_text="When your Cash falls to $3 or below at the start of any round, Clause Reader fires once per run: immediately gain $8. A lifeline written into the fine print — the clause only activates when you're genuinely on the edge, not as a routine income stream.", rarity="Uncommon", salary=10, groups={"paypal-mafia"}, mafia=true, hint="economy: one-time Cash burst when runway…", effect={type="economy", scaling="conditional_burst", hook="before", primitive_hint="dollars", engine_status="executable", magnitude="8 dollars (once per run, triggers when cash <= 3)", ke_complement=false}, dsl={hook="first_hand_drawn", gate={g="count", per="cash", op="<=", val=3}, ops={{k="grant", what="cash", amount=8}}, once=true, once_scope="run"}},
  {key="f_steve-jobs", effect_brief="Miss target -> big x Rev (bigger the shortfall); +x1.5 Rev if <=3 Founders", set="Founder", name="Quadrant King", short="King", ability_name="Reality Distortion Field", ability_text="Reality Distortion Field. When you Ship a hand whose ARR falls short of the blind's target, the Quadrant King refuses the verdict and wills it upward: a large x Rev that grows the further you fell short (up to about x2.6 on a near-total miss, fading toward x1.6 as you approach target). Conviction over crowds: if you hold 3 or fewer Founders total, every scoring App Type also gains a flat x1.5 Rev.", rarity="Legendary", salary=40, groups={"homebrew-computer-club", "mac-team"}, hint="Revenue-per-user (Rev), conditional 'imp…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="x_mult", base=3.6, coef=-2, per="arr_ratio", gate={g="arr_ratio", stage="pre_after", op="<", val=1}}, {k="scale", field="x_mult", base=1.5, coef=0, gate={g="count", per="others", op="<=", val=2}}}}},
  {key="f_steve-perlman", effect_brief="Once/run: clears one compatibility clash", set="Founder", name="Clutch Conjurer", short="Conjurer", ability_name="Phil Walked In", ability_text="The first time you play a hand containing tech cards from two or more Layers that share a compatibility clash, the clash is silently dissolved for that hand — all cards score as if fully compatible. The burst fires exactly once per run: Clutch Conjurer can pull the impossible demo out of nowhere one time, but only one time.", rarity="Common", salary=5, hint="once per run, nullifies one compatibility…", effect={type="utility", scaling="conditional_burst", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="1 clash nullified, fires once per run on the first qualifyi…", ke_complement=false}, dsl={hook="before", ops={{k="clear_clash", amount=1}}, once=true, once_scope="run"}},
  {key="f_steve-wozniak", effect_brief="×3 Rev, flat, no conditions", set="Founder", name="Four-Night Wizard", short="Wizard", ability_name="Single-Board Elegance", ability_text="Four-Night Wizard applies a flat ×3 to your Rev — doing in software, with a handful of cheap Users, what others need a full rack of hardware to do. No conditions, no ramp: the elegance is just there.", rarity="Rare", salary=20, groups={"homebrew-computer-club"}, hint="Flat ×3 Rev — the whole machine on one b…", effect={type="xmult", scaling="flat", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="3", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=3.0, coef=0}}}},
  {key="f_steven-hao", effect_brief="+8 Users/stacked card; +2 Users/stacked card ever shipped", set="Founder", name="Stealth Deployer", short="Deployer", ability_name="Pipeline Depth", ability_text="Each tech card in your played hand that stacks depth in a Layer it shares with another card gives +8 Users this Ship. Each Ship also permanently deepens this founder's stack: it gains +2 Users for every stacked-depth card you have ever shipped, so each subsequent scoring pass lands denser than the last.", rarity="Common", salary=5, groups={"ioi-gold-medalists", "competitive-programming-cohort", "ai-engineer-wave"}, hint="+Users (Users), scaling-over-time", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={ {k="scale", field="chips", base=0, coef=8, per="redundant_cards"}, {k="acc", field="chips", base=0, coef=2, state="depth", when="post", step="ship", inc_per="redundant_cards", reset_on={"selling_self"}} } }},
  {key="f_stewart-brand", effect_brief="Each ante: +1 copy of your highest-Users Tech card", set="Founder", name="Whole-Earth Impresario", short="Impresario", ability_name="The Catalog Grows", ability_text="At the start of each ante while Whole-Earth Impresario is in your roster, the best tool in your kit is catalogued and duplicated — one copy of your highest-Users Tech card is permanently added to your deck. The Catalog grows thicker with every funding stage, compounding across the run so that by late antes your deck is stacked with copies of your strongest fit.", rarity="Uncommon", salary=10, groups={"Merry Pranksters", "whole-earth-crowd"}, hint="each ante you keep Whole-Earth Impresario…", effect={type="generation", scaling="scaling_persistent", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="1 tech card per ante (Layer = Market preferred Layer; rando…", ke_complement=false}, dsl={hook="setting_blind", once=true, once_scope="ante", ops={{k="gen", kind="copy_card", which="highest"}}}},
  {key="f_sualeh-asif", effect_brief="+8 Rev per repeat of an App Type (own tab each type)", set="Founder", name="Ghost Tabber", short="Tabber", ability_name="Zero Entropy Tab", ability_text="Ghost Tabber keeps a silent confidence counter for each App Type. Every time you Ship that same App Type, its locked-in tab grows: +8 Rev the first time you call it, +16 the next, +24 after that, and so on — a self-fulfilling prediction that pays off the more you commit to a lane. Switching to a different App Type starts that type's tab fresh at +8.", rarity="Common", salary=5, groups={"ai-engineer-wave", "mit-class-of-2022", "international-mathematical-olympiad-alumni"}, hint="conditional +Rev (speculative pre-scorin…", effect={type="plus_mult", scaling="conditional_burst", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=8, coef=8, when="post", key="scoring_name", state="tab", reset_on={"selling_self","blind_lost"}}}}},
  {key="f_swyx", effect_brief="+40+10×Layers Users; once/ante on AI hand", set="Founder", name="Namespace Coiner", short="Coiner", ability_name="The Naming Moment", ability_text="The first time each ante a played hand includes at least one AI-layer card, gain +Users equal to 40 + 10 × (distinct layers in that hand). The burst only fires on AI-layer hands and scales with stack breadth; it does nothing in a round you don't touch AI.", rarity="Common", salary=5, groups={"ai-engineer-wave"}, hint="conditional burst of +Users the first tim…", effect={type="plus_chips", scaling="conditional_burst", hook="individual", primitive_hint="chips", engine_status="executable", magnitude="40 + 10 * distinct_layers_in_hand  (once per ante; requires…", ke_complement=false}, dsl={hook="individual", ops={{k="scale", field="chips", base=40.0, coef=10.0, per="distinct_layers"}}, gate={g="layer_present", layer="AI"}, once=true, once_scope="ante"}},
  {key="f_syaru-shirley-lin", effect_brief="+12 Rev if hand spans 3+ Layers; 1/ante", set="Founder", name="Drowned Deal", short="Deal", ability_name="Pulled Out A Random Number", ability_text="When you Ship an App Type whose coverage touches 3 or more distinct Layers, Drowned Deal adds +12 Rev this hand. Fires once per ante — a burst that only triggers when the product is genuinely full-stack.", rarity="Common", salary=5, hint="add +Rev when a played App Type spans 3…", effect={type="plus_mult", scaling="conditional_burst", hook="individual", primitive_hint="mult", engine_status="executable", magnitude="+12 if distinct_layers >= 3, once per ante", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="scale", field="mult", base=12, coef=0}}, once=true, once_scope="ante"}},
  {key="f_thomas-wolf", effect_brief="+1 Users/App Type shipped; x2 if all-distinct Layers", set="Founder", name="Seven-Night Replicator", short="Replicator", ability_name="Open Weights", ability_text="Each round Seven-Night Replicator is active, every App Type your team has ever Shipped contributes +1 Users permanently to your base — the community keeps building on your work. If the hand you Ship is a fully open, full-stack release (every played card a distinct Layer), that whole bonus is DOUBLED — radical transparency over secrecy.", rarity="Common", salary=5, groups={"open-source-ai", "french-ai-founders"}, hint="+Users (Users) scaling-over-time, conditi…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="chips", base=0, coef=1, per="distinct_app_types_shipped"}, {k="scale", field="chips", base=0, coef=1, per="distinct_app_types_shipped", gate={g="all_distinct_layers"}}}}},
  {key="f_tim-berners-lee", effect_brief="+6 Rev per distinct Layer in hand", set="Founder", name="Royalty Refuser", short="Refuser", ability_name="Public Domain Dividend", ability_text="While Royalty Refuser is hired, every scored hand gains a flat +6 Rev for each distinct Layer it spans. A single-Layer play earns little; a product touching all five Layers cashes the dividend in full. He asked for nothing in return, and that zero-friction grant is exactly what lets a full-stack product capture the full spread.", rarity="Legendary", salary=40, hint="+6 Rev per distinct Layer in the scored…", effect={type="plus_mult", scaling="flat", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="6 * distinct_layers", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", base=0, coef=6, per="distinct_layers"}}}},
  {key="f_tim-oreilly", effect_brief="+1 Rev, +1 more each round (persists); +1 Founder slot", set="Founder", name="Namer of Things", short="Things", ability_name="Frame the Platform", ability_text="Frame the Platform: each round you play, Namer of Things grows the platform he named — gain +1 Rev, increasing by +1 every subsequent round this run (persists). While hired he also opens the ecosystem to one extra Founder (+1 Founder slot).", rarity="Common", salary=5, hint="scaling-over-time + ecosystem multiplier…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0, coef=1.0, state="platform", step="round", when="post"}}}, passive={what="founder_slots", amount=1}, passive={what="founder_slots", amount=1}},
  {key="f_timnit-gebru", effect_brief="+1 permanent Rev each round survived unfired", set="Founder", name="Unfired Parrot", short="Parrot", ability_name="Suppression Rebound", ability_text="Unfired Parrot gains +1 permanent Rev for each round she survives without being sold. The longer they fail to push her out, the louder her pitch gets — the bonus carries into every subsequent round.", rarity="Uncommon", salary=10, groups={"google-brain-alumni", "google-ai-ethics-alumni"}, hint="scaling-over-time + conditional ARR boost", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="unfired", step="round", when="post"}}}},
  {key="f_timothee-lacroix", effect_brief="+Margin once; overkill +50% Cash; +Cash scaling with best ARR", set="Founder", name="Frugal Alchemist", short="Alchemist", ability_name="Sparse Activation", ability_text="At the end of each round your Margin permanently rises by +0.05 the first time only — a structural cost-efficiency lift (capped to one lift per run). Then any ARR beyond the blind target is compressed into +50% extra Cash (overkill compression — value squeezed from spare capacity), plus a frugality bonus of Cash scaling with your best-ever round ARR (accumulated efficiency from every new high you reach).", rarity="Common", salary=5, groups={"ex-meta-llama-team", "ecole-normale-superieure-alumni", "french-ai-ecosystem"}, hint="Margin (compute efficiency → higher margi…", effect={type="economy", scaling="scaling_persistent", hook="after", primitive_hint="dollars", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook='end_of_round', ops={ {k='grant', what='margin', amount=0.05, max=0.05}, {k='grant', what='cash', per='overkill', coef=0.5}, {k='grant', what='cash', per='run_best_arr', coef=0.0005} }}},
  {key="f_tom-brown", effect_brief="+$1 Reserve/Ship; start each rnd +Reserve Cash", set="Founder", name="Curve Whisperer", short="Whisperer", ability_name="Core Resources Dividend", ability_text="Every time you Ship (score a round), your Compute Reserve grows by $1 permanently. At the start of each round you receive Cash equal to the current Reserve — a treasury that never shrinks, only expands. By mid-run the Reserve generates enough income to absorb Salary costs entirely, letting you hire freely without counting pennies.", rarity="Uncommon", salary=10, groups={"ex-openai-diaspora", "anthropic-founding-team"}, hint="each Ship permanently adds $1 to a growin…", effect={type="economy", scaling="scaling_persistent", hook="before", primitive_hint="dollars", engine_status="executable", magnitude="reserve += 1 per Ship; payout = reserve each round_start", ke_complement=false}, dsl={hook="setting_blind", ops={{k="grant", what="cash", per="ships_this_run", coef=1}}}},
  {key="f_tom-gruber", effect_brief="×Layers in hand (Coverage, not Depth)", set="Founder", name="Edge Caser", short="Caser", ability_name="Specification of a Conceptu…", ability_text="Edge Caser's Knowledge node lays a shared ontology over your whole build. (1) Interop — any two Layer cards that the Compatibility graph would normally treat as incompatible are scored as if fully compatible, removing fit penalties for the round. (2) Translation ×Rev — at scoring he grants ×Rev equal to the number of distinct Layers present in your built hand, so a broad, full-coverage stack multiplies hard while a single-Layer hand barely benefits. He rewards Coverage, not Depth: stacking duplicates of one Layer does nothing for him.", rarity="Rare", salary=20, groups={"stanford-ksl-knowledge-sharing-effort", "siri-cofounders"}, hint="Universal cross-Layer ×Rev that scales w…", effect={type="xmult", scaling="flat", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=true}, dsl={hook="joker_main", ops={{k="clear_clash", amount="all"}, {k="scale", field="x_mult", base=0, coef=1, per="distinct_layers"}}}},
  {key="f_tom-perkins", effect_brief="×2.5 Rev, 1st time each Layer played", set="Founder", name="Falcon Skipper", short="Skipper", ability_name="Eliminate the White-Hot Risk", ability_text="When you Ship a hand containing a card from a Layer that has never appeared in any previously played hand this run, that hand's Rev is multiplied by ×2.5 — a one-time burst for resolving the critical unknown. Each Layer can only trigger this once per run (five bursts maximum). Re-playing a proven Layer gives nothing; Falcon Skipper only pays to eliminate the unknown, not to repeat a safe bet.", rarity="Uncommon", salary=10, hint="xMult x2.5 burst the first time each Laye…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="x2.5 per first-Layer-seen trigger (max 5 triggers total per…", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="new_layers", op=">=", val=1}, ops={{k="scale", field="x_mult", base=1, coef=1.5, per="new_layers"}}}},
  {key="f_tommy-davis", effect_brief="+2 Rev per Founder on your roster", set="Founder", name="Four-Word General", short="General", ability_name="Portfolio Conviction", ability_text="Conviction compounds when you bet on people. Each Founder on your roster (including Four-Word General himself) grants +2 Rev to every hand. A two-Founder roster is +4 Rev; a five-Founder roster is +10 Rev — the more people you back, the harder the whole portfolio pays.", rarity="Common", salary=5, hint="each Founder hired permanently adds 1 ext…", effect={type="generation", scaling="scaling_persistent", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 bonus shop tech card per Founder currently hired (includi…", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="mult", per="founders_hired_this_run", coef=2}}}},
  {key="f_tony-hsieh", effect_brief="+Users, grows +3 each round held", set="Founder", name="Happiness Dealer", short="Dealer", ability_name="Seventy-Five Percent Return", ability_text="Each hand played while Happiness Dealer is held, gain +(4 + 3 × rounds_held) Users (Users). The first round it's a modest +7; by round 4 it's +16. The longer the culture is embedded, the louder the signal — no acquisition budget needed, the happy customer does the recruiting.", rarity="Common", salary=5, hint="adds Users each hand — repeat-customer wo…", effect={type="plus_chips", scaling="scaling_per_round", hook="individual", primitive_hint="chips", engine_status="executable", magnitude="4 + 3*rounds_held", ke_complement=false}, dsl={hook="after", ops={{k="scale", field="chips", base=4.0, coef=3.0, per="rounds_held"}}}},
  {key="f_toran-bruce-richards", effect_brief="+2 Users per App Type played this run", set="Founder", name="Accidental Summoner", short="Summoner", ability_name="Viral Drop", ability_text="When you play a hand this round, gain +2 Users (Users) for each distinct App Type you have played this run — the star count compounds with variety. On the round you first hire Accidental Summoner, trigger a one-time momentum burst: double your current Users score for that hand only.", rarity="Common", salary=5, groups={"agentic-ai-pioneers", "ai-engineer-wave"}, hint="scaling-over-time (stars/momentum) → +chi…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="chips", base=0.0, coef=2, per="distinct_app_types_shipped"}}}},
  {key="f_travis-kalanick", effect_brief="x1.5 Rev + skim 2% ARR as Cash when ARR >= 2x target", set="Founder", name="Running Shoes Guy", short="Guy", ability_name="Surge Pricing", ability_text="Surge Pricing: when a Shipped hand's running ARR reaches 2x or more of the current Blind's target ('peak demand'), Revenue-per-user (Rev) is multiplied by 1.5x AND you skim 2% of that hand's ARR as Cash.", rarity="Uncommon", salary=10, hint="×Rev (conditional, demand-scaled)", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}, ops={{k="scale", field="x_mult", base=1.5, coef=0}, {k="scale", field="dollars", per="running_arr", stage="pre_after", coef=0.02}}}},
  {key="f_vannevar-bush", effect_brief="×2 Rev while 2+ other Founders active", set="Founder", name="One-Page Czar", short="Czar", ability_name="One Page to the Oval Office", ability_text="One-Page Czar built the scaffold before the battle started — academia, industry, and government locked in place so everyone else's work counted more. While One-Page Czar is hired and at least 2 other Founders are also active, every Ship scores ×2 Rev. The multiplier is fixed and unconditional once the threshold is met: all three legs of the triangle must be present for it to fire.", rarity="Uncommon", salary=10, groups={"MIT", "National Defense Research Committee", "Office of Scientific Research and Development"}, hint="flat xmult on every Ship when 2+ other Fo…", effect={type="xmult", scaling="flat", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="2.0 if active_founders >= 3 else 1.0", ke_complement=false}, dsl={hook="joker_main", gate={g="count", per="others", op=">=", val=2}, ops={{k="scale", field="x_mult", base=2.0, coef=0}}}},
  {key="f_varun-mohan", effect_brief="Once/blind: all-distinct-Layer hand grants +40 Users, +8 per Layer", set="Founder", name="Monday Executioner", short="Executioner", ability_name="Weekend Reboot", ability_text="Monday Executioner doesn't half-pivot. The first time each blind you ship a hand where every tech card is a distinct Layer — a clean, fully-rebuilt full-stack, no redundant duplicates — gain +40 Users, plus +8 Users for each distinct Layer in the hand. A burst that rewards total commitment over cherry-picking, and fires once per blind.", rarity="Common", salary=5, groups={"mit-alumni"}, hint="one-time +Users burst triggered when you…", effect={type="plus_chips", scaling="conditional_burst", hook="before", primitive_hint="chips", engine_status="executable", magnitude="40 + 8 * max(0, distinct_layers_discarded - 1)", ke_complement=false}, dsl={hook="before", gate={g="all_distinct_layers"}, ops={{k="scale", field="chips", base=40, coef=8, per="distinct_layers"}}, once=true, once_scope="blind"}},
  {key="f_vinod-khosla", effect_brief="+1 perm ×Rev token each 2× overkill", set="Founder", name="Scale Whisperer", short="Whisperer", ability_name="Black Swan Bet", ability_text="Scale Whisperer has one question before anything else: can it scale? When you Ship a hand that scores at least 2× the blind's target ARR, Scale Whisperer's conviction compounds — gain +1 permanent ×Rev token (stacks). If you Pivot while Scale Whisperer is hired, you lose no Cash and instead gain +1 Users flat. He does nothing for modest wins; a true blowout triggers exponential upside.", rarity="Uncommon", salary=10, hint="Scaling-over-time × conditional probabili…", effect={type="xmult", scaling="scaling_persistent", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}, ops={{k="acc", field="x_mult", base=1.0, coef=0.12, state="xmult", when="post", step="ship", max=33}}}},
  {key="f_walden-yan", effect_brief="+Rev per Layer if 3+ Layers played", set="Founder", name="Eighty-Percent Dropout", short="Dropout", ability_name="Eighty Percent Threshold", ability_text="Eighty-Percent Dropout tracks the moment the product stops being a demo and becomes the actual team. When you Ship a hand covering 3 or more distinct Layers, gain a one-time +Rev equal to 1 + 1 per distinct Layer played this hand (+4 at 3 Layers, +5 at 4, +6 at full 5). Below 3 Layers, no effect — broad coverage across the full stack is what triggers the inflection.", rarity="Common", salary=5, groups={"ioi-gold-medalists", "thiel-fellows", "competitive-programming-cohort", "ai-engineer-wave"}, hint="one-time +Rev burst when the played hand…", effect={type="plus_mult", scaling="conditional_burst", hook="after", primitive_hint="mult", engine_status="executable", magnitude="1 + distinct_layers_played (when distinct_layers_played >=…", ke_complement=false}, dsl={hook="after", gate={g="count", per="distinct_layers", op=">=", val=3}, ops={{k="scale", field="mult", base=1.0, coef=1, per="distinct_layers"}}}},
  {key="f_walt-disney", effect_brief="+1 perm Rev/round; +2 perm on 2× overkill", set="Founder", name="House-Deed Dreamer", short="Dreamer", ability_name="Bet the House", ability_text="House-Deed Dreamer bets the house on every moonshot — and the moonshots become institutions. Each round this Founder is held, gain +1 permanent Rev (the compound legacy grows). When you Ship and your ARR exceeds the blind's target by 2× or more, convert the overkill surplus into +2 permanent Rev for the rest of the run: the win doesn't just win once, it keeps generating.", rarity="Uncommon", salary=10, hint="scaling-over-time + overkill-to-permanent…", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="after", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="rev_hold", step="round", when="post"}, {k="acc", field="mult", base=0.0, coef=2.0, state="rev_blowout", step="ship", when="post", gate={g="arr_ratio", stage="pre_after", op=">=", val=2}}}}},
  {key="f_wang-xing", effect_brief="+15 Users per all-distinct-Layer Ship, snowballs (persistent)", set="Founder", name="Thousand-City Closer", short="Closer", ability_name="Countryside First", ability_text="Thousand-City Closer encircles crowded markets from the uncovered flanks — lanes the mainline rivals ignore. Every time you Ship an App Type whose cards each cover a different Layer (a clean flank, no lane piled on twice), permanently grow a Users bonus: +15 Users, then +15 more for each such flank Ship after. Methodical, full-coverage expansion snowballs the longer you keep entering from open ground.", rarity="Uncommon", salary=10, hint="Users (Users) — scaling-over-time + condi…", effect={type="plus_chips", scaling="scaling_persistent", hook="joker_main", primitive_hint="chips", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0, coef=15, step="ship", state="plus_chips", when="post", gate={g="all_distinct_layers"}}}}},
  {key="f_ward-cunningham", effect_brief="First hand each round: dissolve all compatibility clashes", set="Founder", name="Open Gate Keeper", short="Keeper", ability_name="Wiki Wiki Shuttle", ability_text="Open Gate Keeper removes every lock on tools that just want to work together. The first hand you Ship each round, all compatibility clashes are dissolved — every tech card blocked by a clash mismatch scores as if fully compatible. Fires once per round; resets each new round.", rarity="Uncommon", salary=10, groups={"agile-manifesto"}, hint="utility — when compatibility clashes in h…", effect={type="utility", scaling="conditional_burst", hook="before", primitive_hint=nil, engine_status="data_only", magnitude="fires if active_clashes >= 3; clears all clash penalties fo…", ke_complement=false}, dsl={hook="before", once=true, once_scope="blind", ops={{k="clear_clash", amount="all"}}}},
  {key="f_william-shockley", effect_brief="Each Founder sold/fired pays +$4 Cash", set="Founder", name="Polygraph Tyrant", short="Tyrant", ability_name="Traitorous Eight Dividend", ability_text="Polygraph Tyrant drives away everyone who matters — and they all land somewhere consequential, and pay you back for it. Each time any Founder is removed from your roster (sold or fired), gain $4 Cash. The dividend is paid on every departure, including Polygraph Tyrant's own.", rarity="Rare", salary=20, hint="Each time a Founder leaves your roster (s…", effect={type="generation", scaling="flat", hook="after", primitive_hint=nil, engine_status="data_only", magnitude="1 Founder card added to shop per Founder sold/fired", ke_complement=false}, dsl={hook="selling_card", ops={{k="grant", what="cash", amount=4}}}},
  {key="f_winston-weinberg", effect_brief="Enterprise/Legal: +2 Rev per Ship (stacks); +1 Margin once", set="Founder", name="Hundred-Case Bluff", short="Bluff", ability_name="Prestige Play", ability_text="Hundred-Case Bluff only courts the most prestigious clients. While your Market is Enterprise or Legal, each App you Ship adds a permanent +2 Revenue-per-user (Rev) that stacks for the rest of the run — every prestige sale makes the next one easier. The first time it fires, also permanently raise your Margin by one step (bootstrap-lane reward).", rarity="Common", salary=5, hint="conditional +Rev + scaling-over-time", effect={type="plus_mult", scaling="scaling_persistent", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", gate={g="or", gs={{g="market", attr="industry", value="enterprise"}, {g="market", attr="industry", value="legal"}}}, ops={{k="acc", field="mult", base=0.0, coef=2.0, state="prestige", when="post", step="ship"}, {k="grant", what="margin", amount=0.1, max=0.1}}}},
  {key="f_xavier-niel", effect_brief="+4 perm Users per Infra card scored", set="Founder", name="Price Guillotine", short="Guillotine", ability_name="Tombstone Subscriber", ability_text="Price Guillotine floods the market by slashing what the incumbents never dared to cut. Each time you play a hand, count the Infra-layer cards scored: gain +4 Users per Infra card, permanently. The stack never resets. The longer Price Guillotine is hired, the larger the subscriber base assembled — monopoly breaker, one rollout at a time.", rarity="Common", salary=5, groups={"french-tech-ecosystem", "french-billionaires"}, hint="Permanently gain +Users for each Infra ca…", effect={type="plus_chips", scaling="scaling_persistent", hook="after", primitive_hint="chips", engine_status="executable", magnitude="+4 per Infra card played, accumulated permanently across th…", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="chips", base=0.0, coef=4, inc_per="cards_of_layer", layer="Infra", state="guillotine", when="post"}}}},
  {key="f_yann-lecun", effect_brief="×2.5 Rev once/ante if no AI cards played", set="Founder", name="Gallic Heretic", short="Heretic", ability_name="Paradigm Crack", ability_text="Gallic Heretic bets publicly against the dominant paradigm and waits for reality to catch up. Once per ante, if the scoring hand contains zero AI-layer tech cards, this Founder fires a ×2.5 Rev multiplier on that score — a single vindication burst. The spike is one-shot per ante (it resets each new ante so you can keep betting against consensus). Pairs devastatingly with non-AI App Types that the market currently undervalues.", rarity="Rare", salary=20, groups={"meta-fair-alumni", "turing-award-winners", "deep-learning-godfathers"}, hint="burst ×Rev when you score without any AI…", effect={type="xmult", scaling="conditional_burst", hook="joker_main", primitive_hint="x_mult", engine_status="executable", magnitude="2.5 if no AI-layer card in scored hand this ante (once per…", ke_complement=false}, dsl={hook="joker_main", ops={{k="scale", field="x_mult", base=2.5, coef=0}}, gate={g="not", g1={g="layer_present", layer="AI"}}, once=true, once_scope="ante"}},
  {key="f_yoav-shoham", effect_brief="Clears 1st clash per round automatically", set="Founder", name="Equilibrium Fixer", short="Fixer", ability_name="Equilibrium Correction", ability_text="Equilibrium Fixer doesn't replace the incumbent — he wraps it, patches the error, and harvests the corrected output. The first time each round a tech card in your played hand would be blocked from scoring due to a compatibility clash, Equilibrium Fixer intervenes: the clash is cleared for that card and it scores as if fully compatible. Fires once per round (first occurrence only); resets each new round.", rarity="Common", salary=5, hint="once per round, nullify one compatibility…", effect={type="utility", scaling="conditional_burst", hook="individual", primitive_hint=nil, engine_status="data_only", magnitude="1 clash nullified per round (first occurrence only)", ke_complement=false}, dsl={hook="before", once=true, once_scope="blind", ops={{k="clear_clash", amount=1}}}},
  {key="f_yuhuai-tony-wu", effect_brief="+1 Rev/win token (max 5); resets on loss", set="Founder", name="Loop Whisperer", short="Whisperer", ability_name="STaR Loop", ability_text="Loop Whisperer bootstraps skill from its own output, discarding wrong answers and iterating on what worked. Each round Loop Whisperer is hired AND your team ships (wins the blind), accumulate one Iteration token (max 5); each token adds +1 Rev at score time. When you lose a blind while Loop Whisperer is hired, the tokens reset to 0 and you immediately gain +2 Rev for that round — maximum signal extracted from every failure. Consistent shipping compounds; every wrong answer teaches.", rarity="Common", salary=5, groups={"xai-founding-team", "ex-deepmind"}, hint="scaling-over-time (self-improving Rev)", effect={type="plus_mult", scaling="scaling_per_round", hook="joker_main", primitive_hint="mult", engine_status="executable", magnitude="", ke_complement=false}, dsl={hook="joker_main", ops={{k="acc", field="mult", base=0.0, coef=1.0, state="iter", when="post", step="ship", max=5, reset_on={"blind_lost"}}}}},
  {key="f_yuri-milner", effect_brief="Start of each stage: +$2 Cash per stage reached (snowball)", set="Founder", name="Spreadsheet Cosmonaut", short="Cosmonaut", ability_name="40-Country Model", ability_text="The Spreadsheet Cosmonaut models monetization ceilings the rest of the market hasn't mapped yet, and his projections only get bolder as you scale. At the start of every funding stage, pay out $2 Cash for each stage reached so far — a snowball that compounds the higher you climb. Cash arrives unconditionally: no board seat, no governance strings.", rarity="Uncommon", salary=10, hint="Generates $Cash at the start of each ante…", effect={type="economy", scaling="scaling_persistent", hook="before", primitive_hint="dollars", engine_status="executable", magnitude="2 * distinct_markets_seen_run + (2 if new_non_us_market_thi…", ke_complement=false}, dsl={hook="setting_blind", once=true, once_scope="ante", ops={{k="grant", what="cash", per="ante", coef=2}}}},
}
